-- ═══ EXPAND NEARBY TOWNS SCHEMA ═════════════════════════════
-- Adds detailed fields for seasonal worker town guides and seeds all resort towns.

-- Add new columns to nearby_towns
ALTER TABLE nearby_towns
  ADD COLUMN IF NOT EXISTS state_region TEXT,
  ADD COLUMN IF NOT EXISTS population_permanent INT,
  ADD COLUMN IF NOT EXISTS population_seasonal INT,
  ADD COLUMN IF NOT EXISTS website TEXT,
  ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ DEFAULT now(),
  -- Accommodation & Housing
  ADD COLUMN IF NOT EXISTS staff_housing_available BOOLEAN DEFAULT false,
  ADD COLUMN IF NOT EXISTS avg_rent_weekly TEXT,
  ADD COLUMN IF NOT EXISTS housing_demand TEXT,
  ADD COLUMN IF NOT EXISTS temporary_stay_options TEXT,
  -- Transport & Accessibility
  ADD COLUMN IF NOT EXISTS public_transport_to_resort TEXT,
  ADD COLUMN IF NOT EXISTS parking_availability TEXT,
  ADD COLUMN IF NOT EXISTS distance_to_airport TEXT,
  ADD COLUMN IF NOT EXISTS road_conditions TEXT,
  -- Cost of Living
  ADD COLUMN IF NOT EXISTS weekly_cost_estimate TEXT,
  ADD COLUMN IF NOT EXISTS supermarkets TEXT,
  ADD COLUMN IF NOT EXISTS eating_out TEXT,
  -- Work & Employment
  ADD COLUMN IF NOT EXISTS local_employers TEXT,
  ADD COLUMN IF NOT EXISTS extra_job_opportunities TEXT,
  -- Lifestyle & Amenities
  ADD COLUMN IF NOT EXISTS bars_nightlife TEXT,
  ADD COLUMN IF NOT EXISTS restaurants_cafes TEXT,
  ADD COLUMN IF NOT EXISTS gyms_fitness TEXT,
  ADD COLUMN IF NOT EXISTS shops_services TEXT,
  ADD COLUMN IF NOT EXISTS events_festivals TEXT,
  -- Healthcare & Safety
  ADD COLUMN IF NOT EXISTS medical_facilities TEXT,
  ADD COLUMN IF NOT EXISTS emergency_services TEXT,
  -- Community & Culture
  ADD COLUMN IF NOT EXISTS vibe_atmosphere TEXT,
  ADD COLUMN IF NOT EXISTS international_workforce TEXT,
  ADD COLUMN IF NOT EXISTS social_life TEXT,
  -- Climate
  ADD COLUMN IF NOT EXISTS avg_winter_temp TEXT,
  ADD COLUMN IF NOT EXISTS snowfall_in_town TEXT,
  ADD COLUMN IF NOT EXISTS summer_appeal TEXT,
  -- Practical Tips
  ADD COLUMN IF NOT EXISTS best_time_to_arrive TEXT,
  ADD COLUMN IF NOT EXISTS community_groups TEXT,
  ADD COLUMN IF NOT EXISTS insider_tips TEXT;

-- Add is_primary to resort_nearby_towns
ALTER TABLE resort_nearby_towns
  ADD COLUMN IF NOT EXISTS is_primary BOOLEAN DEFAULT true;

-- Add slug index for fast lookups
CREATE INDEX IF NOT EXISTS idx_nearby_towns_slug ON nearby_towns(slug);

-- ═══ UPDATE EXISTING JINDABYNE ROW ═════════════════════════
UPDATE nearby_towns SET
  state_region = 'New South Wales',
  population_permanent = 7000,
  population_seasonal = 15000,
  website = 'https://www.visitjindabyne.com.au',
  staff_housing_available = true,
  avg_rent_weekly = 'AUD $250–$400/week shared; AUD $450–$700 solo',
  housing_demand = 'Very high — start looking in Feb/Mar for June start. Many workers share houses.',
  temporary_stay_options = 'Hostels (Banjo Paterson Inn, Jindy Inn), Airbnb, caravan parks nearby.',
  public_transport_to_resort = 'Free ski-season shuttle buses to Perisher (Skitube at Bullocks Flat). Thredbo buses available but less frequent. Most workers carpool.',
  parking_availability = 'Free town parking. Resort parking is paid and limited — shuttles recommended.',
  distance_to_airport = 'Canberra Airport ~190km (2hr drive). Sydney Airport ~470km (5hr drive).',
  road_conditions = 'Alpine Way and Kosciuszko Road require snow chains in winter. Roads are well-maintained but can close in heavy snow.',
  weekly_cost_estimate = 'AUD $400–$600/week including rent, food, and transport',
  supermarkets = 'IGA Jindabyne, plus smaller shops. Cooma (60km) has Woolworths and Aldi for bigger shops.',
  eating_out = 'AUD $15–$25 for a pub meal. Coffee ~$5. Good range of cafés and restaurants.',
  local_employers = 'Thredbo Resort, Perisher Resort, Jindabyne hotels and restaurants, rental shops, tour operators.',
  extra_job_opportunities = 'Hospitality in town (bars, restaurants, cafés), retail, childcare, cleaning services.',
  bars_nightlife = 'Banjo Paterson Inn is the main party spot. The Station bar, Lake Jindabyne Hotel. Lively scene on weekends.',
  restaurants_cafes = 'Birchwood Café, Takahagi Sushi, Wildbrumby Distillery, The Terrace. Mix of casual and upscale.',
  gyms_fitness = 'Snowy Mountains Fitness Centre, plus resort gyms with staff access.',
  shops_services = 'Ski hire shops, outdoor gear stores, hairdressers, post office, petrol stations.',
  events_festivals = 'Snowy Mountains Craft Beer Festival, Jindabyne Canoe Club events, resort-hosted parties.',
  medical_facilities = 'Jindabyne Medical Centre (GP), nearest hospital is Cooma Hospital (60km).',
  emergency_services = 'Police, ambulance, fire brigade all in Jindabyne. SES for alpine emergencies.',
  vibe_atmosphere = 'Tight-knit seasonal worker community with a fun, adventurous vibe. Everyone knows everyone by mid-season.',
  international_workforce = 'Large international community — UK, Ireland, South America, Japan. English is primary language.',
  social_life = 'House parties, pub nights, lake activities in summer, hiking, mountain biking. Very social community.',
  avg_winter_temp = '-2°C to 8°C in town (colder on the mountain)',
  snowfall_in_town = 'Occasional dustings but town rarely gets proper snow cover. Resorts get 1.5–2m+ annually.',
  summer_appeal = 'Lake Jindabyne is a major summer destination — kayaking, fishing, mountain biking, hiking.',
  best_time_to_arrive = 'Late May to early June. Some employers start hiring in March.',
  community_groups = 'Jindabyne Seasonal Workers Facebook group, Snowy Mountains Backpackers community.',
  insider_tips = 'Get a Snowy Mountains car and invest in good snow chains. Join the Facebook housing groups early. Staff passes get you discounted food on-mountain.'
WHERE slug = 'jindabyne';

-- ═══ SEED ALL TOWNS ════════════════════════════════════════

-- ── AUSTRALIA / NZ ─────────────────────────────────────────

-- Mount Beauty (Falls Creek)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description,
  population_permanent, population_seasonal, website,
  staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options,
  public_transport_to_resort, parking_availability, distance_to_airport, road_conditions,
  weekly_cost_estimate, supermarkets, eating_out,
  local_employers, extra_job_opportunities,
  bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals,
  medical_facilities, emergency_services,
  vibe_atmosphere, international_workforce, social_life,
  avg_winter_temp, snowfall_in_town, summer_appeal,
  best_time_to_arrive, community_groups, insider_tips)
VALUES (
  'Mount Beauty', 'mount-beauty', 'Australia', 'Victoria', -36.7394, 147.1714,
  'A quiet Kiewa Valley town at the base of Falls Creek. Popular with seasonal workers for its affordability and relaxed lifestyle.',
  1800, 4000, 'https://www.visitmountbeauty.com.au',
  true, 'AUD $180–$300/week shared', 'Moderate — easier to find than other resort towns.', 'Caravan parks, Airbnb, worker lodges at the resort.',
  'Falls Creek Coach Service runs daily in winter. Most workers drive or carpool — 30min winding road.', 'Free in town. Falls Creek has paid day parking.', 'Albury Airport ~120km (1.5hr). Melbourne Airport ~370km (4hr).', 'Bogong High Plains Road is well-maintained but chains required. Can close in heavy snow.',
  'AUD $300–$450/week', 'IGA Mount Beauty, small general stores.', 'AUD $12–$20 pub meals. Limited options — many workers cook at home.',
  'Falls Creek Resort, Mount Beauty hotels, Bogong Horseback Adventures.', 'Hospitality in town, agricultural work in the valley.',
  'The Terminus pub is the main social hub. Quiet nightlife — most action is on-mountain.', 'Roi''s Diner, Bogong Jack''s, The Hollow cafe.', 'Mount Beauty Community Gym.', 'General stores, petrol station, post office.', 'Kangaroo Hoppet (cross-country ski race), Falls Festival.',
  'Mount Beauty Medical Centre (GP). Nearest hospital: Bright Hospital (30km).', 'CFA, ambulance, police in town.',
  'Laid-back, outdoorsy community. Quieter than Jindabyne but tight-knit.', 'Smaller international presence — mostly Australians with some international workers.', 'House BBQs, pub trivia, hiking in Kiewa Valley.',
  '1°C to 10°C', 'Rare snowfall in town — too low elevation.', 'Excellent hiking, cycling, paragliding. Kiewa Valley is beautiful in summer.',
  'Late May. Housing is less competitive than other resorts.', 'Falls Creek Seasonal Workers Facebook group.', 'Buying a cheap car is almost essential. Mount Beauty is much cheaper than living on-mountain at Falls Creek.'
);
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary)
VALUES ((SELECT id FROM resorts WHERE legacy_id='51' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='mount-beauty' LIMIT 1), 32, true);

-- Bright (Mt Hotham)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description,
  population_permanent, population_seasonal, website,
  staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options,
  public_transport_to_resort, parking_availability, distance_to_airport, road_conditions,
  weekly_cost_estimate, supermarkets, eating_out,
  local_employers, extra_job_opportunities,
  bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals,
  medical_facilities, emergency_services,
  vibe_atmosphere, international_workforce, social_life,
  avg_winter_temp, snowfall_in_town, summer_appeal,
  best_time_to_arrive, community_groups, insider_tips)
VALUES (
  'Bright', 'bright', 'Australia', 'Victoria', -36.7313, 146.9553,
  'A charming alpine town in the Ovens Valley, Bright is the main base for Mt Hotham and Dinner Plain workers. Known for its autumn foliage, craft breweries, and outdoor lifestyle.',
  2500, 5000, 'https://www.visitbright.com.au',
  true, 'AUD $200–$350/week shared', 'Moderate — more affordable than on-mountain.', 'Bright Holiday Park, Airbnb, worker share houses.',
  'Hotham bus service runs daily in season. The drive is 50min via Great Alpine Road — steep and winding.', 'Free in town. Hotham has limited paid parking.', 'Albury Airport ~120km. Melbourne Airport ~330km.', 'Great Alpine Road well-maintained. Chains required above Harrietville.',
  'AUD $350–$500/week', 'IGA Bright, small specialty shops.', 'AUD $15–$25. Great café and restaurant scene for a small town.',
  'Mt Hotham Resort, Dinner Plain lodges, Bright hospitality venues.', 'Cycling tourism hospitality, brewery work, agricultural picking.',
  'Bright Brewery is the social hub. A few pubs. Nightlife is mellow.', 'Bright Brewery, Tomahawks, Reed & Co Distillery, numerous cafés.', 'Alpine Health Fitness Centre.', 'Outdoor gear shops, art galleries, general stores.', 'Bright Autumn Festival, mountain bike events.',
  'Alpine Health Bright (urgent care + GP). Nearest major hospital: Wangaratta (75km).', 'Police, ambulance, CFA in town.',
  'Artsy, outdoorsy, food-and-wine-focused. Slightly older demographic than Jindabyne.', 'Smaller international contingent. Mostly Aussie workers.', 'Brewery catch-ups, river swims in summer, cycling culture.',
  '2°C to 11°C', 'Very rare — town is in the valley.', 'One of Victoria''s top cycling destinations. Stunning autumn colours draw tourists.',
  'Late May. Some employers recruit from March.', 'Mt Hotham Seasonal Workers Facebook group.', 'Living in Bright means a long drive up the mountain each day — but the lifestyle and cost savings are worth it.'
);
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary)
VALUES ((SELECT id FROM resorts WHERE legacy_id='53' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='bright' LIMIT 1), 30, true);

-- Methven (Mt Hutt)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description,
  population_permanent, population_seasonal, website,
  staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options,
  public_transport_to_resort, parking_availability, distance_to_airport, road_conditions,
  weekly_cost_estimate, supermarkets, eating_out,
  local_employers, extra_job_opportunities,
  bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals,
  medical_facilities, emergency_services,
  vibe_atmosphere, international_workforce, social_life,
  avg_winter_temp, snowfall_in_town, summer_appeal,
  best_time_to_arrive, community_groups, insider_tips)
VALUES (
  'Methven', 'methven', 'New Zealand', 'Canterbury', -43.6381, 171.6428,
  'A small Canterbury Plains town at the foot of Mt Hutt. Methven is the only real base town and has a classic NZ ski-town feel in winter.',
  1600, 3000, 'https://www.methven.co.nz',
  true, 'NZD $180–$280/week shared', 'Moderate — limited stock but manageable.', 'Methven backpackers, holiday park, worker accommodation at resort.',
  'Mt Hutt shuttle bus operates daily in season. 25min drive up.', 'Free in town. Free resort parking.', 'Christchurch Airport ~100km (1.5hr).', 'Mt Hutt access road is steep and often icy — 4WD recommended.',
  'NZD $300–$450/week', 'Four Square Methven, small shops.', 'NZD $15–$22 pub meals. Limited but decent options.',
  'Mt Hutt ski area (NZSki), Methven Heli-Skiing, local pubs and accommodation.', 'Farm work, café jobs in Christchurch (commutable).',
  'Blue Pub and Brown Pub are the two main spots. Legendary ski-town atmosphere.', 'Café 131, Duplicity Restaurant, pub food.', 'Small community gym.', 'General store, ski hire, petrol station.', 'Mt Hutt opening day party, local rugby.',
  'Methven Medical Centre.', 'Police, fire, ambulance — small but present.',
  'Quintessential small NZ ski town — everyone at the pub knows your name. Kiwi hospitality at its best.', 'Mix of Kiwis, Aussies, and some internationals.', 'Pub culture is strong. House parties, BBQs, ski days together.',
  '0°C to 10°C', 'Occasional frost and light snow in town.', 'Quieter in summer. Jet boating, hiking, cycling nearby.',
  'Late May. Season is June–October.', 'Mt Hutt Workers Facebook group.', 'The Blue Pub is where you''ll meet everyone. Get to know the locals — they''ll look after you.'
);
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary)
VALUES ((SELECT id FROM resorts WHERE legacy_id='54' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='methven' LIMIT 1), 26, true);

-- Queenstown (The Remarkables)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description,
  population_permanent, population_seasonal, website,
  staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options,
  public_transport_to_resort, parking_availability, distance_to_airport, road_conditions,
  weekly_cost_estimate, supermarkets, eating_out,
  local_employers, extra_job_opportunities,
  bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals,
  medical_facilities, emergency_services,
  vibe_atmosphere, international_workforce, social_life,
  avg_winter_temp, snowfall_in_town, summer_appeal,
  best_time_to_arrive, community_groups, insider_tips)
VALUES (
  'Queenstown', 'queenstown', 'New Zealand', 'Otago', -45.0312, 168.6626,
  'New Zealand''s adventure capital and the base for The Remarkables, Coronet Peak, and Cardrona. A vibrant international town with world-class nightlife, dining, and outdoor activities year-round.',
  16000, 35000, 'https://www.queenstownnz.co.nz',
  true, 'NZD $250–$400/week shared; NZD $500+ solo', 'Extremely high — start searching 2–3 months early. Facebook groups essential.', 'YHA Queenstown, Nomads, Airbnb, hostel-to-lease pipeline.',
  'NZSki shuttle buses to Remarkables and Coronet Peak (free with staff pass). Orbus local buses.', 'Town parking is limited and can be paid. Resort shuttles recommended.', 'Queenstown Airport in town (domestic + some Australian flights). Nearest international: Christchurch (5hr drive).', 'Well-maintained roads. Chains sometimes required for Remarkables access road.',
  'NZD $400–$600/week', 'Countdown, New World, PAK''nSAVE (Frankton). Good selection.', 'NZD $18–$30. Wide range from budget to high-end.',
  'NZSki (Remarkables, Coronet Peak), Skyline Queenstown, AJ Hackett Bungy, hotels, bars, restaurants.', 'Massive hospitality sector year-round. Tourism, adventure tourism, retail, events.',
  'World Bar, Rhino''s, Cowboys, Little Blackwood, 1876. One of NZ''s best nightlife scenes.', 'Fergburger (iconic), Flame Bar & Grill, Botswana Butchery, Bespoke Kitchen, hundreds more.', 'Queenstown Gym, CrossFit Queenstown, resort staff gyms.', 'Extensive — outdoor gear shops, supermarkets, banks, everything you need.', 'Queenstown Winter Festival (huge), Gay Ski Week, numerous events all season.',
  'Lakes District Hospital, Queenstown Medical Centre.', 'Full services — police, fire, ambulance, mountain rescue.',
  'Electric, international, adventure-focused. The ultimate working holiday destination. Fast-paced and social.', 'Hugely international — UK, Ireland, France, Argentina, Brazil, Japan. English primary but very multilingual.', 'Incredible social scene. Staff parties, bar crawls, adventure activities, hiking, lake swims.',
  '-1°C to 8°C', 'Light snow occasionally. Town sits on Lake Wakatipu — milder than the mountains.', 'Equally popular in summer. Bungy, jet boats, hiking, cycling, lake activities.',
  'Late April to mid-May for June start. Housing fills fast.', 'Queenstown Seasonal Workers Facebook group (very active), Queenstown NZ Community.', 'Fergburger queue tip: go at 3am. Get your IRD number sorted before arriving. The Remarkables staff bus is free — use it.'
);
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary)
VALUES ((SELECT id FROM resorts WHERE legacy_id='7' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='queenstown' LIMIT 1), 8, true);

-- ── JAPAN ──────────────────────────────────────────────────

-- Kutchan / Hirafu (Niseko)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description,
  population_permanent, population_seasonal, website,
  staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options,
  public_transport_to_resort, parking_availability, distance_to_airport, road_conditions,
  weekly_cost_estimate, supermarkets, eating_out,
  local_employers, extra_job_opportunities,
  bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals,
  medical_facilities, emergency_services,
  vibe_atmosphere, international_workforce, social_life,
  avg_winter_temp, snowfall_in_town, summer_appeal,
  best_time_to_arrive, community_groups, insider_tips)
VALUES (
  'Hirafu / Kutchan', 'hirafu-kutchan', 'Japan', 'Hokkaido', 42.8631, 140.6889,
  'The main base for Niseko United. Hirafu village is where most international workers live, eat, and party. Kutchan is the larger neighbouring town with better amenities and lower rents.',
  15000, 30000, 'https://www.niseko.ne.jp/en/',
  true, '¥30,000–¥60,000/month (~$280–$550 USD). Staff housing common.', 'High — employer-provided housing is the norm for resort jobs.', 'Guesthouses, share houses, employer dorms.',
  'Free Niseko United shuttle bus connects all four resorts and Hirafu. Kutchan is 15min by car.', 'Free at most accommodation. Resort parking available.', 'New Chitose Airport (Sapporo) ~110km (2hr drive, bus available).', 'Roads well-maintained and plowed regularly. Studded tyres required.',
  '¥40,000–¥60,000/month ($370–$550 USD) with staff housing', 'Max Valu and Lucky supermarkets in Kutchan. Convenience stores (7-Eleven, Lawson) everywhere.', '¥800–¥1,500 for ramen/curry. Western restaurants ¥1,500–¥3,000. Incredible food scene.',
  'Niseko United resorts (Hanazono, Hirafu, Niseko Village, Annupuri), hotels, restaurants, ski schools.', 'English-teaching, hospitality, outdoor guiding, retail.',
  'Bar Gyu+, Toshiro''s, Wild Bill''s. International party scene, especially in Hirafu.', 'A-Bu-Cha, Niseko Ramen, Kabuki, Bang Bang, Prativo. World-class dining from ramen to fine dining.', 'Kutchan Gymnasium, yoga studios in Hirafu.', 'Rhythm Japan (gear shop), convenience stores, Kutchan has hardware stores and services.', 'Niseko Classic car rally, snow festivals, resort events.',
  'Niseko International Clinic (English-speaking). Kutchan Hospital for emergencies.', 'Police, fire, ambulance. Mountain rescue via resort patrol.',
  'International party village meets Japanese countryside. Unique cultural mix of Australian, British, and Japanese cultures.', 'One of the most international ski towns in the world. Heavy Australian, British, Canadian presence. English widely spoken in Hirafu.', 'Legendary après scene. International parties, onsen (hot spring) visits, powder day celebrations.',
  '-10°C to -2°C. One of the snowiest places on earth.', 'Heavy snowfall — town gets buried. 15+ metres of snow annually.', 'Quieter but rafting, cycling, golf, and hiking are popular. Many workers stay for summer too.',
  'Late November for December start. Some positions start as early as November.', 'Niseko Seasonal Workers Facebook group, GaijinPot forums.', 'Learn basic Japanese — it goes a long way. The powder is unreal but the cold is serious. Onsen after riding is essential.'
);
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary)
VALUES ((SELECT id FROM resorts WHERE legacy_id='3' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='hirafu-kutchan' LIMIT 1), 5, true);

-- Furano
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description,
  population_permanent, population_seasonal, website,
  staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options,
  public_transport_to_resort, parking_availability, distance_to_airport, road_conditions,
  weekly_cost_estimate, supermarkets, eating_out,
  local_employers, extra_job_opportunities,
  bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals,
  medical_facilities, emergency_services,
  vibe_atmosphere, international_workforce, social_life,
  avg_winter_temp, snowfall_in_town, summer_appeal,
  best_time_to_arrive, community_groups, insider_tips)
VALUES (
  'Furano', 'furano', 'Japan', 'Hokkaido', 43.3424, 142.3831,
  'Furano is both the resort and the town — the ski area is right on the edge of town. A more authentically Japanese experience than Niseko, with lavender fields, local eateries, and a quieter vibe.',
  21000, 25000, 'https://www.snowfurano.com',
  true, '¥25,000–¥45,000/month. Staff housing common.', 'Moderate — less competitive than Niseko.', 'Guesthouses, employer housing, share apartments.',
  'Resort is walkable from town. JR Furano station connects to Sapporo/Asahikawa.', 'Free parking at resort and in town.', 'Asahikawa Airport ~60km (1hr). New Chitose Airport ~150km (2.5hr).', 'Well-maintained. Snow tyres essential.',
  '¥35,000–¥50,000/month', 'Co-op supermarket, small local shops. More limited than Kutchan.', '¥700–¥1,200 for local meals. Furano is famous for its curry and cheese.',
  'Furano Ski Resort (Prince Hotels), local ryokans, restaurants.', 'Farm work in lavender season, English teaching.',
  'Quiet nightlife — a few izakayas and bars. Nothing like Niseko''s party scene.', 'Furano Cheese Factory, Kumagera (traditional Japanese), local ramen shops.', 'Town sports centre.', 'Small shops, convenience stores, ski hire.', 'Furano Belly Button Festival (summer), snow festivals.',
  'Furano Hospital.', 'Full emergency services.',
  'Authentic Japanese small-town life with great skiing. Peaceful and cultural.', 'Growing but still predominantly Japanese. More immersive cultural experience.', 'Quiet and community-focused. Onsen visits, local festivals.',
  '-12°C to -3°C', 'Heavy snowfall — town gets plenty of snow.', 'Famous lavender fields draw tourists. Beautiful hiking and cycling.',
  'Late November.', 'Furano Seasonal Workers group.', 'Learn Japanese — less English spoken than Niseko. The curry is a must-try. Great powder with no crowds.'
);
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary)
VALUES ((SELECT id FROM resorts WHERE legacy_id='45' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='furano' LIMIT 1), 2, true);

-- Hakuba
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description,
  population_permanent, population_seasonal, website,
  staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options,
  public_transport_to_resort, parking_availability, distance_to_airport, road_conditions,
  weekly_cost_estimate, supermarkets, eating_out,
  local_employers, extra_job_opportunities,
  bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals,
  medical_facilities, emergency_services,
  vibe_atmosphere, international_workforce, social_life,
  avg_winter_temp, snowfall_in_town, summer_appeal,
  best_time_to_arrive, community_groups, insider_tips)
VALUES (
  'Hakuba', 'hakuba', 'Japan', 'Nagano', 36.6983, 137.8617,
  'Hakuba Village hosted the 1998 Winter Olympics and is Japan''s most famous alpine area outside Hokkaido. The village IS the resort — multiple ski areas line the valley with accommodation scattered throughout.',
  9000, 20000, 'https://www.hakubavalley.com',
  true, '¥30,000–¥55,000/month. Employer housing common.', 'High — book early through employer or housing groups.', 'Guesthouses, backpacker lodges, employer dorms.',
  'Free shuttle buses between Hakuba Valley resorts. JR train to Nagano (1hr).', 'Free at most accommodations and resorts.', 'Matsumoto Airport ~70km. Narita/Haneda via Nagano shinkansen (~3hr).', 'Well-maintained valley roads. Chains/snow tyres required.',
  '¥35,000–¥55,000/month', 'A-Coop supermarket, Big convenience store, 7-Eleven.', '¥800–¥1,500. Great local ramen and izakayas.',
  'Hakuba Valley resorts (Happo-One, 47, Goryu, etc.), hotels, ski schools, restaurants.', 'English teaching, outdoor guiding (summer rafting/hiking).',
  'The Pub, Mocking Bird, Rabbit Hole. Good international bar scene.', 'Sharaku, Mimi''s, Sounds Like Café, local soba shops.', 'Evergreen Outdoor Centre gym, yoga studios.', 'Rhythm Japan, ski hire shops, convenience stores.', 'Hakuba Snow Festival, resort events, torch-lit night skiing.',
  'Hakuba Clinic (English-speaking doctors available). Azumi General Hospital nearby.', 'Full services available.',
  'Mix of Olympic village heritage and international ski culture. More spread out than Niseko.', 'Large Australian and British community. English widely spoken in tourist areas.', 'Active social scene — bar nights, powder day celebrations, onsen culture.',
  '-8°C to 2°C', 'Good snowfall in the valley.', 'Green season is popular — hiking, rafting, mountain biking in the Japanese Alps.',
  'Late November to early December.', 'Hakuba Seasonal Workers Facebook group.', 'Get a bicycle or car — the valley is spread out. The 1998 Olympic facilities are still in use.'
);
