VALUES (
  'Myoko', 'myoko', 'Japan', 'Niigata', 36.8628, 138.1856,
  'Myoko is a collection of onsen villages at the base of Mt Myoko. Less touristy than Niseko or Hakuba, it offers deep powder, hot springs, and an authentic Japanese mountain experience.',
  30000, 35000, 'https://myokokogen.net/en/',
  true, '¥20,000–¥40,000/month', 'Low — affordable and available.', 'Pensions, ryokans, employer housing.',
  'Local buses between resort areas. JR Myoko Kogen station.', 'Free parking at resorts.', 'Nearest airport: Niigata (~2hr). Tokyo via shinkansen to Joetsu-Myoko (~2hr).', 'Heavy snowfall roads, well-plowed.',
  '¥30,000–¥40,000/month', 'Small supermarkets and convenience stores.', '¥600–¥1,000. Very affordable local meals.',
  'Myoko resorts (Akakura, Suginohara, etc.), local ryokans.', 'Limited — resort and hospitality focused.',
  'Very quiet nightlife. A few bars in Akakura Onsen area.', 'Local ramen shops, izakayas, pension dining.', 'Limited.', 'Basic amenities.', 'Local festivals and onsen events.',
  'Local clinic. Hospital in Joetsu city.', 'Emergency services available.',
  'Quiet, authentic, powder-focused. For workers who want deep Japan immersion.', 'Small but growing international community.', 'Onsen culture, quiet evenings, powder day stoke.',
  '-10°C to -2°C', 'Extremely heavy snowfall — one of Japan''s snowiest areas.', 'Green season hiking on Mt Myoko.',
  'Late November.', 'Myoko seasonal worker groups.', 'Japanese language is almost essential here. The powder makes up for the lack of nightlife.'
);
