-- Vail Village
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Vail Village', 'vail-village', 'United States', 'Colorado', 39.6403, -106.3742, 'Vail is a purpose-built European-style village at the base of Vail Mountain. One of the largest and most famous ski resorts in North America, owned by Vail Resorts.', 5300, 15000, 'https://www.vail.com', true, 'USD $800–$1,500/month shared. Staff housing available through Vail Resorts.', 'Very high — Vail Resorts provides subsidised staff housing for most employees.', 'Staff housing, shared rentals in nearby Minturn or Eagle-Vail.', 'Free town bus system. Free resort shuttle. Nearby towns connected by ECO Transit.', 'Parking structures available (paid in village, free at some lots). Staff parking available.', 'Eagle County Regional Airport ~35mi. Denver International ~100mi (2hr via I-70).', 'I-70 is well-maintained but notorious for ski traffic and closures during storms.', 'USD $500–$800/week. Expensive.', 'City Market (Kroger). Better options in Avon/Edwards nearby.', 'USD $15–$40. High-end dining scene.', 'Vail Resorts (massive employer), hotels, restaurants, ski schools.', 'Hospitality in Avon/Edwards/Minturn. Construction.', 'Red Lion, Garfinkel''s, The George. Good après scene.', 'Sweet Basil, Mountain Standard, La Tour, Minturn Saloon (nearby).', 'Vail Athletic Club, Vail Recreation District.', 'Full village amenities. More options in Avon/Edwards.', 'Vail Snow Daze, GoPro Mountain Games (summer), Bravo! music festival.', 'Vail Health Hospital — excellent facility.', 'Full services — police, fire, ambulance.', 'Upscale resort village with a strong international seasonal worker culture. Expensive but the benefits (free ski pass) are world-class.', 'International — South American (especially Argentine/Chilean), Australian, European.', 'Active social scene. Staff housing has community vibe. Minturn is the workers'' hangout.', '-12°C to -1°C', 'Regular snowfall at village elevation (2,500m).', 'Mountain biking, hiking, golf, festivals.', 'October for November start.', 'Vail Valley Seasonal Workers Facebook group.', 'Minturn is the affordable, fun alternative to living in Vail Village. The employee ski pass covers multiple Vail Resorts mountains.');
