-- Aspen
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Aspen', 'aspen', 'United States', 'Colorado', 39.1911, -106.8175, 'The most glamorous ski town in America. Four mountains, celebrity culture, world-class dining, and eye-watering property prices. Seasonal workers are the backbone of this town.', 7400, 20000, 'https://www.aspensnowmass.com', true, 'USD $700–$1,200/month shared. Employer housing common.', 'Extremely high. Employee housing programs essential.', 'Employer housing, shared rentals in Basalt/Carbondale (30min down-valley).', 'RFTA free bus system connects Aspen, Snowmass, Basalt, Carbondale. Excellent public transit.', 'Free parking at Buttermilk. Paid parking in town.', 'Aspen/Pitkin County Airport (in town — short runway). Eagle/Vail Airport ~70mi.', 'Highway 82 well-maintained. Independence Pass closes in winter.', 'USD $500–$900/week', 'Clark''s Market, City Market in Basalt.', 'USD $20–$50+. Notoriously expensive dining.', 'Aspen Skiing Company (all 4 mountains), The Little Nell, hotels, restaurants.', 'Down-valley hospitality, retail, construction.', 'Eric''s Bar, Aspen Tap, The J-Bar, Belly Up (live music). Excellent nightlife.', 'Matsuhisa, Ajax Tavern, White House Tavern, CP Burger. Celebrity chef restaurants.', 'Aspen Recreation Centre (world-class), ARC.', 'Full luxury amenities — high-end shops, services.', 'X Games, Aspen Ideas Festival, Food & Wine Festival, music festivals.', 'Aspen Valley Hospital.', 'Full services.', 'Glamorous but the seasonal worker community is down-to-earth and tight-knit. Stark wealth contrast.', 'Large South American community (especially Argentine). Australian, European.', 'House parties in Basalt/Carbondale, bar nights in town, outdoor adventures.', '-12°C to 0°C', 'Good snowfall.', 'World-class summer destination — hiking, biking, festivals.', 'October for late November start.', 'Aspen Seasonal Workers group.', 'Live down-valley (Basalt/Carbondale) for affordable rent — the RFTA bus is free and excellent. The four-mountain pass is incredible value.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='16' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='aspen' LIMIT 1), 0, true);

-- Breckenridge
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Breckenridge', 'breckenridge', 'United States', 'Colorado', 39.4817, -106.0384, 'A historic gold-mining town turned ski resort. Breckenridge has a charming Main Street, is part of the Vail Resorts Epic Pass family, and has one of Colorado''s liveliest seasonal worker scenes.', 5100, 15000, 'https://www.breckenridge.com', true, 'USD $700–$1,200/month shared. Vail Resorts staff housing available.', 'Very high. Staff housing essential.', 'Staff housing, shared rentals in Frisco/Silverthorne (cheaper).', 'Free Ride bus system. Summit Stage connects Summit County towns. Gondola from town to resort.', 'Free parking at some lots. Paid in town.', 'Denver International ~100mi (2hr via I-70).', 'I-70 to Hwy 9. Well-maintained. Weekend ski traffic is brutal.', 'USD $450–$700/week', 'City Market. More options in Frisco/Silverthorne.', 'USD $12–$30. Great Main Street dining.', 'Vail Resorts, Main Street restaurants, hotels, shops.', 'Hospitality across Summit County. Outlets at Silverthorne.', 'Gold Pan Saloon (oldest bar in CO), Cecilia''s, Downstairs at Eric''s.', 'Hearthstone, Modis, Empire Burger, Breckenridge Brewery.', 'Breckenridge Recreation Center (excellent).', 'Historic Main Street shops, ski hire, basics.', 'Ullr Fest (snow god parade), International Snow Sculpture Championships, July 4th fireworks.', 'Breckenridge Medical Center.', 'Full services.', 'Fun, historic, accessible. Great vibe for first-time seasonal workers. More affordable than Vail/Aspen.', 'International — South American, Australian, European workers.', 'Main Street bar crawls, house parties, hot tub culture, hiking.', '-12°C to -2°C at 2,926m elevation', 'Regular snowfall. Town is at high elevation.', 'Mountain biking, hiking, festivals. Year-round tourism.', 'October for mid-November start.', 'Breck Seasonal Workers Facebook group.', 'Frisco and Silverthorne offer cheaper rent with easy bus access. The Gold Pan is a Breck institution.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='17' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='breckenridge' LIMIT 1), 0, true);

-- Jackson
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Jackson', 'jackson', 'United States', 'Wyoming', 43.4799, -110.7624, 'Gateway to Grand Teton and Yellowstone national parks. Jackson is a western town with an iconic town square (elk antler arches), world-class skiing, and a wild contrast between billionaire homeowners and seasonal workers.', 10500, 20000, 'https://www.jacksonhole.com', true, 'USD $800–$1,400/month shared. Housing crisis is well-documented.', 'Extreme — the worst housing market in US ski towns. Workers live in cars and tents.', 'START bus employee housing, Victor/Driggs ID (over Teton Pass, 30min), employer housing.', 'START bus free system. Resort shuttle from town.', 'Free at resort. Paid in town.', 'Jackson Hole Airport (in Grand Teton NP — stunning). Also Idaho Falls Airport ~90mi.', 'Teton Pass to Idaho can be treacherous. Town roads well-maintained.', 'USD $500–$800/week. Very expensive.', 'Albertsons, Smith''s. Decent selection.', 'USD $15–$35. Great dining but pricey.', 'Jackson Hole Mountain Resort (JHMR), hotels, restaurants, national park services.', 'National park jobs (summer especially), Victor/Driggs hospitality.', 'The Rose, Million Dollar Cowboy Bar, Snake River Brewing.', 'Snake River Brewing, Persephone, Bin22, Lotus Café.', 'Jackson Hole Athletic Club, Teton Sports Club.', 'Full town amenities. Outdoor gear shops, art galleries.', 'Grand Teton Music Festival, Old West Days, ski events.', 'St. John''s Medical Center.', 'Full services — plus Grand Teton NP rangers.', 'Wild West meets extreme wealth. The worker community is resilient and adventurous. Wildlife (moose, elk, bears) in town.', 'International but less so than Colorado resorts. Strong South American presence.', 'Bar scene, house parties, backcountry skiing, national park adventures.', '-15°C to -4°C. Cold and snowy.', 'Good snowfall at town elevation (1,900m).', 'World-class summer — hiking in the Tetons, Yellowstone access, rafting.', 'September–October.', 'Jackson Hole Seasonal Workers Facebook group.', 'Victor/Driggs Idaho is where savvy workers live — cheaper rent, 30min over Teton Pass. The Million Dollar Cowboy Bar is a must-visit.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='18' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='jackson' LIMIT 1), 20, true);

-- Park City
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Park City', 'park-city', 'United States', 'Utah', 40.6461, -111.4980, 'A historic silver mining town turned ski mecca. Home to the Sundance Film Festival, two major resorts, and the 2002 Winter Olympics legacy. Just 35 min from Salt Lake City.', 8500, 20000, 'https://www.parkcity.org', true, 'USD $700–$1,200/month shared.', 'High. SLC commute is an option.', 'Staff housing, shared rentals, SLC commute.', 'Free city bus system. UTA bus to Salt Lake City.', 'Free transit centre parking. Resort parking available.', 'Salt Lake City International Airport ~35mi (35min).', 'I-80 to SR-224. Well-maintained.', 'USD $450–$700/week', 'Fresh Market, Whole Foods, more options in SLC.', 'USD $15–$35. Historic Main Street dining.', 'Vail Resorts (PCMR), Deer Valley, hotels, restaurants, film festival.', 'SLC offers massive job market 35min away.', 'No Name Saloon, High West Distillery, The Spur. Utah liquor laws are quirky but nightlife exists.', 'Handle, Riverhorse, High West, Silver Star Café.', 'PC MARC (excellent rec centre), Basin Recreation.', 'Full town amenities plus SLC access.', 'Sundance Film Festival (January — the town transforms), Miners Day, arts events.', 'Park City Medical Center, University of Utah Hospital in SLC.', 'Full services.', 'Culture meets skiing. Film festival energy, Olympic heritage, proximity to SLC makes it uniquely accessible.', 'International seasonal workers plus SLC commuters.', 'Main Street bar crawls, hot tubbing, backcountry skiing, SLC nightlife.', '-10°C to -1°C', 'Regular snowfall. Town at 2,100m.', 'Mountain biking, hiking, Olympic facilities, summer festivals.', 'October for November start.', 'Park City Seasonal Workers group.', 'Utah has unique alcohol laws — 5% ABV limit on draft beer. SLC commute is viable and much cheaper. Sundance volunteering gets you free film access.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='19' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='park-city' LIMIT 1), 0, true);

-- Big Sky
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Big Sky', 'big-sky', 'United States', 'Montana', 45.2833, -111.4014, 'A spread-out resort community in the Gallatin Canyon. Big Sky is more of a collection of lodges and developments than a traditional town. Bozeman (45min) is where many workers live.', 3500, 10000, 'https://www.bigsky.com', true, 'USD $700–$1,200/month shared. Staff housing available.', 'High — Big Sky is spread out with limited rental stock.', 'Staff housing, Bozeman rentals, shared houses.', 'Skyline bus to Bozeman. Resort shuttles.', 'Free resort parking.', 'Bozeman Yellowstone International Airport ~50mi (1hr).', 'US-191 through Gallatin Canyon — scenic but can be icy.', 'USD $400–$650/week', 'Roxy''s Market in Big Sky. Full options in Bozeman.', 'USD $15–$30.', 'Big Sky Resort, Lone Mountain Ranch, hotels, restaurants.', 'Bozeman has a robust job market and Montana State University economy.', 'Tipsy Moose, Chet''s, Scissorbills. Small scene.', 'Horn & Cantle, Olive B''s, Lotus Pad.', 'Big Sky Community Gym.', 'Basic — Bozeman for full services.', 'Big Sky Big Grass (bluegrass festival), pond skim.', 'Big Sky Medical Center.', 'Sheriff, fire, ambulance.', 'Remote, uncrowded, massive terrain. Workers who love solitude and big mountains thrive here.', 'Growing international community.', 'Quieter scene. Bozeman weekends, outdoor adventures, house parties.', '-14°C to -3°C', 'Good snowfall.', 'Yellowstone NP access, fly fishing, hiking, rafting.', 'October–November.', 'Big Sky Worker Community groups.', 'Bozeman living gives you a real town with nightlife and culture — worth the commute. Yellowstone is right there.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='20' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='big-sky' LIMIT 1), 0, true);

-- Steamboat Springs
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Steamboat Springs', 'steamboat-springs', 'United States', 'Colorado', 40.4850, -106.8317, 'A genuine western Colorado town known for its natural hot springs, champagne powder, and rodeo heritage. More of a real town than a resort village.', 13000, 20000, 'https://www.steamboat.com', true, 'USD $600–$1,100/month shared.', 'High but more manageable than Vail/Aspen.', 'Staff housing, shared rentals.', 'Free Steamboat Springs Transit (SST) bus. Gondola from base.', 'Free bus system parking. Resort parking available.', 'Steamboat Springs Airport (Hayden, 25mi). Denver ~160mi (3hr).', 'US-40 and Rabbit Ears Pass. Can be snowy.', 'USD $400–$600/week', 'City Market, Safeway.', 'USD $12–$25. Good restaurant scene.', 'Steamboat Resort, Old Town restaurants, hotels, ranches.', 'Agricultural work, downtown hospitality, hot springs jobs.', 'Old Town Pub, Schmiggity''s Live Music, Tap House. Great nightlife for the size.', 'Café Diva, Winona''s, Creekside Café, Mambo Italiano.', 'Old Town Hot Springs (pool, gym, water slide — worker favourite).', 'Full downtown amenities. Real town services.', 'Winter Carnival, Pro Rodeo Series (summer), hot springs events.', 'UCHealth Yampa Valley Medical Center.', 'Full services.', 'Authentic Colorado mountain town. Cowboy culture meets ski culture. The hot springs make this special.', 'International seasonal workers plus long-term locals.', 'Hot springs soaks, bar nights, rodeo events, hiking, tubing.', '-12°C to -2°C', 'Famous champagne powder — very dry, light snow.', 'Hot springs, hiking, cycling, tubing on the Yampa River.', 'October–November.', 'Steamboat Seasonal Workers group.', 'Old Town Hot Springs is the ultimate après spot — cheap and amazing. Steamboat''s powder is legendarily light.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='21' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='steamboat-springs' LIMIT 1), 0, true);

-- Stowe
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Stowe', 'stowe', 'United States', 'Vermont', 44.4654, -72.6874, 'A quintessential New England village with a white church steeple, covered bridges, and Vermont charm. Stowe Mountain Resort is 7 miles from the village.', 4500, 9000, 'https://www.stowe.com', true, 'USD $600–$1,000/month shared.', 'Moderate.', 'Inn rooms, shared rentals, employer housing.', 'Mountain Road Shuttle (free in season). 10min drive to resort.', 'Free resort parking. Village parking available.', 'Burlington International Airport ~40mi (45min).', 'Mountain Road (Rte 108) well-maintained. Smuggler''s Notch closes in winter.', 'USD $350–$550/week', 'Shaw''s, small local markets.', 'USD $12–$28. Excellent farm-to-table dining.', 'Vail Resorts (Stowe), Trapp Family Lodge, inns, restaurants.', 'Ben & Jerry''s factory (Waterbury), brewery jobs, Burlington economy.', 'The Matterhorn, Doc Ponds, Cork. Good après scene.', 'Hen of the Wood, Doc Ponds, Harrison''s, Trapp Family Lodge.', 'Stowe Arena, local gyms.', 'Charming village shops, galleries.', 'Stowe Winter Carnival, foliage season events, Trapp Family concerts.', 'Copley Hospital (Morrisville), UVM Medical in Burlington.', 'Full services.', 'Classic New England ski town. Quaint, charming, family-oriented. Vermont values (local food, craft beer, sustainability).', 'Less international than western resorts. Mostly American workers.', 'Craft beer scene, farm-to-table dining, outdoor activities, Burlington nightlife nearby.', '-14°C to -3°C', 'Good snowfall. Classic nor''easter storms.', 'Stunning foliage season (September–October). Hiking, cycling.', 'October–November.', 'Stowe community groups.', 'Burlington is 40min away and has a fantastic food/beer scene. Vermont''s craft beer culture is world-class.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='22' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='stowe' LIMIT 1), 10, true);

-- Telluride
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Telluride', 'telluride', 'United States', 'Colorado', 37.9375, -107.8123, 'A box canyon town surrounded by 4,000m peaks. Telluride is stunningly beautiful, culturally rich, and remote. A free gondola connects the historic town to Mountain Village.', 2600, 6000, 'https://www.tellurideskiresort.com', true, 'USD $700–$1,200/month shared. Employer housing options.', 'High. Very limited housing stock.', 'Employer housing, shared rentals, Montrose commute.', 'Free gondola between town and Mountain Village. Free Galloping Goose bus.', 'Free at some lots. Paid parking in town.', 'Telluride Regional Airport (limited commercial). Montrose Airport ~65mi (1.5hr).', 'Highway 145. Remote. Can be challenging in storms.', 'USD $400–$650/week', 'Clark''s Market. Limited options.', 'USD $15–$35. Excellent dining for the size.', 'Telluride Ski Resort, hotels, restaurants.', 'Limited — remote location. Montrose for additional work.', 'There Bar, Last Dollar Saloon, New Sheridan. Small but fun scene.', 'La Marmotte, 221 South Oak, Brown Dog Pizza.', 'Telluride Gym, outdoor fitness.', 'Small town basics. Art galleries.', 'Telluride Film Festival, Bluegrass Festival, Blues & Brews — world-class cultural events.', 'Telluride Medical Center.', 'Full services.', 'Artsy, adventurous, remote, breathtaking. The box canyon setting is unlike anywhere else.', 'Smaller international community. Passionate outdoor enthusiasts.', 'Festival culture, bar nights, backcountry skiing, ice climbing.', '-13°C to -2°C', 'Good snowfall at 2,667m.', 'Festival season is incredible. Hiking, via ferrata, mountain biking.', 'October–November.', 'Telluride community groups.', 'The free gondola is a game-changer — you can live in Mountain Village and commute to town for free. The festivals make Telluride culturally special.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='23' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='telluride' LIMIT 1), 0, true);

-- Ketchum (Sun Valley)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Ketchum', 'ketchum', 'United States', 'Idaho', 43.6807, -114.3637, 'The town at the base of Sun Valley Resort — America''s first destination ski resort (est. 1936). Ketchum has Hemingway heritage, excellent dining, and a relaxed Idaho mountain town vibe.', 3000, 8000, 'https://www.visitsunvalley.com', true, 'USD $600–$1,000/month shared.', 'High but improving.', 'Staff housing, shared rentals, Hailey (15mi south) is cheaper.', 'KART free bus system connects Ketchum, Sun Valley, Hailey.', 'Free resort parking.', 'Friedman Memorial Airport (Hailey, 12mi). Boise Airport ~150mi (2.5hr).', 'Highway 75 well-maintained.', 'USD $400–$600/week', 'Atkinsons'' Market, Hailey has more options.', 'USD $12–$30. Great dining scene.', 'Sun Valley Resort (Sinclair family), hotels, restaurants.', 'Hailey offers additional hospitality/retail jobs.', 'Whiskey Jacques, The Casino, Cellar Pub. Classic ski town bars.', 'Rickshaw, Enoteca, The Pioneer Saloon (famous), Cristina''s.', 'Sun Valley Athletic Club, YMCA.', 'Ketchum shops, galleries, basics. Hailey for more.', 'Sun Valley Film Festival, Wagon Days, Jazz Festival.', 'St. Luke''s Wood River Medical Center (Ketchum).', 'Full services.', 'Old-school ski town charm with modern amenities. Less corporate than Vail-owned resorts. Hemingway''s favourite town.', 'Growing international presence.', 'Pioneer Saloon culture, outdoor adventures, hot springs nearby.', '-13°C to -2°C', 'Regular snowfall.', 'Fly fishing, hiking, mountain biking. Sun Valley Lodge pool.', 'October–November.', 'Wood River Valley community groups.', 'Hailey is where workers live — cheaper and the KART bus is free. The Pioneer Saloon is a must-visit.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='24' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='ketchum' LIMIT 1), 2, true);

-- Mammoth Lakes
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Mammoth Lakes', 'mammoth-lakes', 'United States', 'California', 37.6485, -118.9721, 'A high-altitude Eastern Sierra town surrounded by volcanic peaks. Mammoth Mountain is right there, and the town has a distinctly Californian mountain vibe — less polished than Tahoe, more real.', 8000, 15000, 'https://www.visitmammoth.com', true, 'USD $600–$1,100/month shared.', 'High. Limited housing stock.', 'Staff housing, shared rentals.', 'Free town trolley. Free resort shuttles.', 'Free parking at many lots. Resort parking available.', 'Mammoth Yosemite Airport (limited commercial). LAX ~310mi (5hr).', 'US-395 well-maintained. Tioga Pass (to Yosemite) closes in winter.', 'USD $400–$600/week', 'Vons supermarket.', 'USD $12–$25.', 'Mammoth Mountain (Alterra), hotels, restaurants.', 'Eastern Sierra tourism, Yosemite (summer).', 'Clocktower Cellar, Lakanuki, Mammoth Brewing Company.', 'Petra''s, Good Life Café, Mammoth Brewing, Toomey''s.', 'Mammoth Strength Gym, hot springs.', 'Full town amenities.', 'Mammoth Film Festival, Bluesapalooza, pond skim.', 'Mammoth Hospital.', 'Full services.', 'California mountain culture. Active, outdoorsy, geological wonderland. Hot springs everywhere.', 'International seasonal workers, Californians.', 'Hot springs soaking, bar scene, backcountry skiing, rock climbing.', '-10°C to 1°C at 2,400m', 'Heavy snowfall — can get buried.', 'Yosemite access, hiking, climbing, hot springs, fishing.', 'October–November.', 'Mammoth Seasonal Workers group.', 'The natural hot springs are everywhere and free — learn the locals'' secret spots. Bring chains for the 395.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='25' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='mammoth-lakes' LIMIT 1), 5, true);

-- Crested Butte
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Crested Butte', 'crested-butte', 'United States', 'Colorado', 38.8697, -106.9878, 'The last great Colorado ski town — remote, funky, and fiercely independent. A former coal mining town with colourful Victorian buildings and some of the most extreme terrain in Colorado.', 1700, 5000, 'https://www.skicb.com', true, 'USD $600–$1,000/month shared.', 'High but small community is helpful.', 'Staff housing, shared rentals, employer lodging.', 'Free Mountain Express bus between town and resort (3mi).', 'Free parking at both town and resort.', 'Gunnison-Crested Butte Regional Airport ~30mi. Denver ~230mi (4hr).', 'Highway 135 to Gunnison. Kebler Pass closes in winter.', 'USD $400–$600/week', 'Clark''s Market.', 'USD $12–$28.', 'Crested Butte Mountain Resort (Vail Resorts), restaurants, hotels.', 'Limited — Gunnison has Western Colorado University economy.', 'The Eldo, Kochevar''s, Talk of the Town. Legendary dive bars.', 'Secret Stash, Marchitelli''s, Slogar (famous fried chicken).', 'Crested Butte Athletic Club.', 'Small town basics. Colourful Elk Avenue shops.', 'Crested Butte Film Festival, Flauschink, Vinotok, wildflower festival.', 'Crested Butte Medical Center.', 'Full services.', 'Funky, artistic, extreme. This is where Colorado''s best skiers go. Anti-corporate, community-driven.', 'Smaller international presence. Passionate locals.', 'Dive bar culture, backcountry skiing, community events.', '-14°C to -3°C', 'Heavy snowfall at 2,700m.', 'Wildflower capital of Colorado. Mountain biking, hiking.', 'October–November.', 'Crested Butte community groups.', 'The Eldo is the social hub — everyone ends up there. Crested Butte has the best extreme terrain in Colorado and the most character.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='26' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='crested-butte' LIMIT 1), 0, true);

-- ── EUROPE — FRANCE ────────────────────────────────────────

-- Chamonix
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Chamonix', 'chamonix', 'France', 'Haute-Savoie', 45.9237, 6.8694, 'The birthplace of alpinism and one of the world''s most iconic mountain towns. Chamonix sits at the foot of Mont Blanc and has a vibrant, international atmosphere year-round. A real town with real character.', 9000, 25000, 'https://www.chamonix.com', true, '€400–€700/month shared. Staff housing from some employers.', 'Very high — start searching 2–3 months early.', 'Gîtes, shared apartments, seasonal worker hostels.', 'Free Chamonix Bus connects all ski areas and villages in the valley. Train (Mont Blanc Express).', 'Town parking available (some free, some paid). Resort parking at lifts.', 'Geneva Airport ~90km (1hr). Closest major airport.', 'Autoroute Blanche (A40) to Geneva. Mont Blanc Tunnel to Italy. Valley roads well-maintained.', '€350–€550/week', 'Casino, Carrefour Contact, M&S Food. Good selection.', '€10–€25. Excellent dining — French cuisine, international options.', 'Compagnie du Mont-Blanc (ski lifts), hotels, restaurants, mountain guide companies, outdoor shops.', 'Hospitality, guiding, English teaching, retail. Geneva commute possible.', 'MBC (Micro Brasserie de Chamonix), Chambre Neuf, Elevation 1904, Jekyll Bar. Fantastic après.', 'MBC, La Calèche, Munchie, Poco Loco, Le Bistrot. World-class food scene.', 'Centre Sportif Richard Bozon (pool, ice rink, gym), climbing gyms.', 'Full town amenities — banks, pharmacy, outdoor gear shops galore.', 'Fête des Guides, UTMB (ultra trail — huge), Cosmo Jazz Festival.', 'Hôpital de Chamonix, numerous medical centres.', 'Full services — PGHM (mountain rescue — world-famous).', 'The ultimate mountain town. Serious alpinism culture mixed with French joie de vivre. International, cosmopolitan, year-round.', 'Hugely international — British, Scandinavian, Eastern European, South American. English widely spoken.', 'Incredible après scene, trail running community, mountaineering culture, French café lifestyle.', '-5°C to 3°C in town', 'Regular snowfall at valley level (1,035m).', 'Summer is massive — UTMB, hiking, paragliding, climbing. Year-round destination.', 'November for December start. Summer: May.', 'Chamonix Seasonal Workers Facebook group (very active).', 'The Mont Blanc Unlimited pass covers everything. Learn basic French — it''s France, not an international resort village. MBC brewery is the social hub.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='2' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='chamonix' LIMIT 1), 0, true);

-- Val d'Isère
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Val d''Isère', 'val-disere', 'France', 'Savoie', 45.4481, 6.9800, 'A high-altitude resort village at 1,850m with exceptional skiing linked to Tignes (Espace Killy). Famous for its legendary après scene, World Cup races, and British seasonal worker culture.', 1600, 8000, 'https://www.valdisere.com', true, '€400–€800/month shared. Staff housing from hotels/restaurants.', 'Very high. Employer housing preferred.', 'Staff accommodation, shared apartments.', 'Free navette (shuttle) buses around the resort. Connected to Tignes.', 'Village parking available. Day lots.', 'Chambéry Airport ~140km. Geneva Airport ~220km. Lyon Airport ~220km.', 'D902 — closes in heavy snow (Iseran pass closed in winter). Bourg-Saint-Maurice access road.', '€400–€600/week', 'Sherpa supermarket, Casino.', '€12–€25. Good dining scene.', 'Hotels, restaurants, ski schools (ESF, Oxygène), lift company.', 'Limited — resort-focused. Tignes nearby.', 'Dick''s Tea Bar (legendary), Petit Danois, Bananas, Cocorico. World-famous après.', 'La Fruitière, L''Atelier d''Edmond, Le Blizzard, mountain restaurants.', 'Centre Aquasportif (pool, gym).', 'Ski shops, basics.', 'Critérium de la Première Neige (World Cup), end-of-season events.', 'Medical centre in resort. Bourg-Saint-Maurice hospital.', 'Pisteurs-secouristes, gendarmerie.', 'International party resort with serious skiing. British-dominated seasonal culture. High altitude, high energy.', 'Very British seasonal workforce. Also Scandinavian, Eastern European.', 'Dick''s Tea Bar defines the social scene. Late nights, early powder mornings.', '-8°C to 0°C', 'Heavy snowfall at 1,850m.', 'Quiet in summer. Some hiking.', 'November for December start.', 'Val d''Isère Saisonniers Facebook group.', 'Dick''s Tea Bar is an institution. Staff housing is crucial — the rental market is tiny. Learn some French for your employers.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='27' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='val-disere' LIMIT 1), 0, true);

-- Val Thorens
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Val Thorens', 'val-thorens', 'France', 'Savoie', 45.2975, 6.5800, 'Europe''s highest ski resort at 2,300m. A purpose-built resort in the Three Valleys — the world''s largest ski area. Guaranteed snow, massive terrain, and a young, international party atmosphere.', 200, 6000, 'https://www.valthorens.com', true, '€350–€650/month. Staff housing standard.', 'Employer housing is the norm.', 'Staff accommodation almost exclusively.', 'Free resort navettes. Connected to Méribel and Courchevel via slopes.', 'Underground car parks.', 'Chambéry ~120km. Lyon ~200km. Geneva ~180km.', 'Single access road from Moûtiers. Can close in storms.', '€350–€500/week', 'Small Sherpa supermarket.', '€10–€22. Resort restaurants.', 'Hotels, restaurants, bars, ski school, lift company.', 'Very limited — self-contained resort.', 'Malaysia Bar, Folie Douce (legendary après), 360 Bar. Party capital of the Alps.', 'Folie Douce, La Maison, Le Chalet de la Marine.', 'Spa and fitness centre.', 'Basic resort shops and ski hire.', 'Rise Festival (electronic music in the mountains), end-of-season parties.', 'Medical centre in resort.', 'Pisteurs, gendarmerie.', 'Pure ski party resort. No pretension, no old-town charm — just snow, skiing, and nightlife. Young crowd.', 'Very international — British, Scandinavian, Eastern European, French.', 'Non-stop nightlife. Staff parties, mountain-top DJs at Folie Douce.', '-10°C to -2°C', 'Resort IS at snow level — heavy snow.', 'Closed in summer (ghost town).', 'November.', 'Val Thorens Saisonniers Facebook group.', 'The altitude takes a few days to adjust to. Folie Douce is the best après in the Alps. The resort completely shuts down in summer.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='28' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='val-thorens' LIMIT 1), 0, true);

-- Méribel
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Méribel', 'meribel', 'France', 'Savoie', 45.3967, 6.5656, 'The heart of the Three Valleys with chalet-style architecture (unique among purpose-built resorts). Very British — sometimes called "Little Britain in the Alps." Great intermediate skiing.', 2000, 8000, 'https://www.meribel.net', true, '€400–€700/month. Staff housing common.', 'High. Employer housing essential.', 'Staff chalets, shared apartments.', 'Free resort navettes. Three Valleys lift system.', 'Resort parking available.', 'Chambéry ~100km. Lyon ~190km. Geneva ~170km.', 'Road from Moûtiers — well-maintained.', '€350–€550/week', 'Sherpa, Spar.', '€12–€25.', 'Chalets, hotels, restaurants, ski schools (ESF, Magic, BASS).', 'Limited — resort focused. Moûtiers in the valley.', 'La Folie Douce (Rond Point), Le Pub, O''Sullivans, Jack''s Bar. Very British après.', 'La Folie Douce, Le Lodge du Village, L''Ekrin.', 'Parc Olympique (pool, ice rink).', 'Resort basics, ski hire.', 'Méribel parties, Three Valleys events.', 'Medical centre in resort.', 'Pisteurs, gendarmerie.', 'British chalet holiday paradise. The most British resort in France. Staff work hard, play hard.', 'Dominated by British workers. Also French, Scandinavian, Eastern European.', 'British pub culture transplanted to the Alps. House parties, bar nights, fancy dress.', '-8°C to 1°C', 'Good snowfall at 1,450m.', 'Summer mountain biking and hiking available.', 'November for December start.', 'Méribel Seasonaires Facebook group.', 'The chalet host job is a Méribel classic — cooking and hosting for British holidaymakers. Rond Point (Folie Douce) is the après institution.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='29' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='meribel' LIMIT 1), 0, true);

-- Courchevel
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Courchevel', 'courchevel', 'France', 'Savoie', 45.4153, 6.6347, 'The most luxurious ski resort in the world. Courchevel 1850 is where billionaires ski. Multiple villages at different altitudes offer varying price points. Staff are the engine of the luxury machine.', 2500, 10000, 'https://www.courchevel.com', true, '€400–€800/month. Staff housing essential.', 'Very high. Nearly all workers need employer housing.', 'Staff accommodation, lower village apartments.', 'Free navettes between Courchevel villages (1300, 1550, 1650, 1850). Three Valleys access.', 'Underground parking. Village is semi-pedestrian.', 'Courchevel Altiport (private jets). Chambéry ~110km. Lyon ~200km.', 'Road from Moûtiers — well-maintained.', '€400–€650/week', 'Small supermarkets in each village level.', '€15–€50+. Some of France''s most expensive restaurants. Staff eat at employer venues.', 'Luxury hotels (Palace-rated), Michelin restaurants, chalets, ski schools.', 'Very limited — resort luxury industry focused.', '1850: La Mangeoire, Kalico, Le Tremplin. Less party-focused than Val Thorens.', 'Le Chabichou (Michelin), Le 1947 (Michelin), Bel Air, La Saulire.', 'Aquamotion (world-class aquatic centre).', 'Luxury retail (Chanel, Dior), basic services in lower villages.', 'Luxury events, fashion shows, gastronomy events.', 'Medical centre in resort.', 'Pisteurs, gendarmerie.', 'The service industry capital of the Alps. Working here means serving the ultra-wealthy. Incredible experience, demanding work.', 'French, Eastern European, British. Service-oriented workforce.', 'Staff community socialises separately from guests. Lower village bars, staff parties.', '-8°C to 0°C', 'Good snowfall across village levels.', 'Some summer activity but much quieter.', 'November.', 'Courchevel Saisonniers group.', 'Courchevel 1650 (Moriond) is where staff life happens — cheaper, more social. Working in luxury hospitality here is a CV goldmine.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='30' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='courchevel' LIMIT 1), 0, true);

-- Morzine
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Morzine', 'morzine', 'France', 'Haute-Savoie', 46.1797, 6.7094, 'A traditional Savoyard village in the Portes du Soleil — one of the world''s largest ski areas spanning France and Switzerland. Morzine has authentic village charm with a massive British seasonal community.', 3000, 12000, 'https://www.morzine.com', true, '€350–€600/month shared.', 'High — very popular with British workers.', 'Shared apartments, staff accommodation, chalet worker live-in.', 'Free navette buses. Pleney and Super Morzine lifts from town centre. Connected to Avoriaz and Les Gets.', 'Town parking. Day lots.', 'Geneva Airport ~80km (1hr). Closest international airport to any French resort.', 'A40 motorway to Cluses, then valley road. Well-maintained.', '€300–€500/week', 'Sherpa, Carrefour Contact.', '€10–€22. Good café culture.', 'Hotels, restaurants, chalet companies, ski schools, Portes du Soleil lift company.', 'Good — close to Geneva for additional work. Summer mountain biking is huge.', 'Dixie Bar, Tibetan Café, Cavern, Bec Jaune Brewery. Great British-style après.', 'Bec Jaune, The Farmhouse, La Chamade, L''Etale.', 'Parc des Dérêches (pool, ice rink, gym).', 'Good town amenities for the size.', 'Morzine-Avoriaz Harley Days, Crankworx (MTB), music events.', 'Medical centre, pharmacy.', 'Full services.', 'Traditional Alpine village with a thriving British seasonal community. Family-friendly, authentic, excellent proximity to Geneva.', 'Very British. Also Dutch, Belgian, Scandinavian, some Aussie/Kiwi.', 'Pub nights, chalet staff parties, mountain biking culture (huge in summer).', '-5°C to 3°C', 'Regular snowfall at 1,000m.', 'Europe''s mountain biking capital. Crankworx host. Hiking, lake swimming.', 'November for December start.', 'Morzine Saisonniers Facebook group (massive and active).', 'Morzine is the most accessible French resort from Geneva — great for weekend trips. Summer season is equally busy with MTB.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='31' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='morzine' LIMIT 1), 0, true);

-- Bourg-Saint-Maurice (Les Arcs / La Plagne)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Bourg-Saint-Maurice', 'bourg-saint-maurice', 'France', 'Savoie', 45.6178, 6.7697, 'The valley town at the base of Les Arcs, with funicular access to the slopes. Also the gateway to La Rosière and close to La Plagne. More affordable and authentic than the resort stations above.', 7500, 12000, 'https://www.lesarcs.com', true, '€300–€500/month shared. Cheaper than resort-level accommodation.', 'Moderate — easier than high-altitude resorts.', 'Shared apartments, gîtes.', 'Funicular from Bourg-Saint-Maurice to Arc 1600 (7min). Free navettes above.', 'Town parking. Day lots.', 'Chambéry ~130km. Geneva ~200km.', 'N90 to Moûtiers, then up-valley. Well-maintained.', '€300–€450/week', 'Intermarché, Casino, local shops.', '€8–€18. Affordable valley dining.', 'Les Arcs (resort stations), La Plagne, hotels, restaurants.', 'Valley hospitality, outdoor activity companies, summer tourism.', 'Quiet town nightlife — resort stations above are livelier.', 'Local restaurants, brasseries, pizza places.', 'Town pool and sports facilities.', 'Full town amenities — supermarkets, banks, pharmacy, hardware.', 'Derby de la Meije, Espace San Bernardo events.', 'Hospital in Bourg-Saint-Maurice.', 'Full services.', 'Real French valley town rather than tourist resort. Affordable living with funicular access to world-class skiing.', 'French workers primarily. Growing international presence.', 'Quieter social scene — resort stations for nightlife. Town has authentic French life.', '-3°C to 5°C (valley is warmer)', 'Occasional snow at valley level (800m).', 'Rafting, hiking, paragliding. Val d''Isère and Tignes nearby in summer.', 'November for December.', 'BSM Saisonniers groups.', 'Living in BSM saves significant money vs resort-level accommodation. The funicular is fast and efficient.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='32' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='bourg-saint-maurice' LIMIT 1), 12, true);

-- ── EUROPE — SWITZERLAND ───────────────────────────────────

-- Zermatt
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Zermatt', 'zermatt', 'Switzerland', 'Valais', 46.0207, 7.7491, 'Car-free village at the foot of the Matterhorn. One of the most iconic ski destinations in the world with year-round glacier skiing. Expensive but extraordinary. Workers live and breathe mountains here.', 5800, 15000, 'https://www.zermatt.ch', true, 'CHF 600–1,200/month shared. Staff housing common from hotels.', 'High. Employer housing essential.', 'Staff accommodation, limited private rentals.', 'Car-free village — everything walkable. Gornergrat railway, cable cars to ski areas.', 'No cars allowed in Zermatt. Park in Täsch (5km) and take the train.', 'Zürich Airport ~230km. Geneva Airport ~240km. Train from Täsch (12min).', 'No road access to Zermatt. Train from Täsch. The village is car-free.', 'CHF 500–$800/week. Swiss prices are high.', 'Coop, Migros (small).', 'CHF 15–35. Swiss prices. Hotel staff meals help.', 'Hotels (Grand, Mont Cervin Palace), Zermatt Bergbahnen (lift company), restaurants.', 'Very limited — Zermatt is self-contained.', 'Papperla Pub, Elsie Bar, Grampi''s, Vernissage. Good bar scene for the size.', 'Chez Vrony (Michelin), Zum See, Whymper Stube.', 'Zermatt fitness facilities. Outdoor lifestyle.', 'Mountain gear shops, luxury boutiques, basics.', 'Zermatt Unplugged (music festival), glacier events.', 'Medical centre in Zermatt. Air Zermatt (helicopter rescue).', 'Full services. Mountain rescue world-class.', 'Awe-inspiring. The Matterhorn dominates everything. Serious mountain culture. Car-free makes it unique.', 'International — Portuguese, German, British, Eastern European, South American.', 'Pub culture, ski touring, mountaineering community, sunset watching with the Matterhorn.', '-8°C to 0°C', 'Regular snowfall at 1,620m.', 'Summer glacier skiing, hiking (Tour de Mont Rosa), climbing.', 'November for December start.', 'Zermatt Seasonal Workers group.', 'No cars means no commute stress. The staff accommodation ecosystem is well-established. Glacier skiing means year-round work is possible.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='4' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='zermatt' LIMIT 1), 0, true);

-- Verbier
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Verbier', 'verbier', 'Switzerland', 'Valais', 46.0964, 7.2283, 'Switzerland''s party resort. Verbier combines world-class freeride terrain with a glamorous, international social scene. Part of the 4 Vallées — one of Switzerland''s largest ski areas.', 3500, 10000, 'https://www.verbier.ch', true, 'CHF 500–1,000/month shared.', 'High. Staff housing helpful.', 'Staff accommodation, shared apartments, Le Châble (valley town, cheaper).', 'Free ski bus. Cable car from Le Châble to Verbier (reduces commute cost).', 'Village parking (paid). Le Châble parking.', 'Geneva Airport ~160km (2hr). Sion Airport ~55km.', 'Mountain road from Le Châble — well-maintained but snowy.', 'CHF 450–700/week', 'Migros, small shops.', 'CHF 15–40.', 'Hotels, restaurants, ski schools (Element Concept, Verbier Ski School), chalets.', 'Le Châble hospitality. Limited off-season.', 'Pub Mont Fort (legendary), Farinet (celeb crowd), Crock No Name. World-class nightlife.', 'La Vache, Chez Dany, Le Carrefour.', 'Centre Sportif, climbing wall.', 'Good village amenities, luxury shops.', 'Verbier Festival (classical music), Xtreme Verbier (freeride world tour finals).', 'Medical centre in Verbier.', 'Full services.', 'Glamorous, extreme, international. Where freeride culture meets champagne lifestyle. The après is legendary.', 'Very international — British, Swedish, French, Australian.', 'Pub Mont Fort culture, freeride community, après circuit.', '-7°C to 1°C', 'Good snowfall at 1,500m.', 'Mountain biking, hiking, festivals.', 'November.', 'Verbier Saisonniers Facebook group.', 'Le Châble is significantly cheaper and the cable car makes it commutable. Pub Mont Fort is THE après bar in Switzerland.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='33' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='verbier' LIMIT 1), 0, true);

-- St. Moritz
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('St. Moritz', 'st-moritz', 'Switzerland', 'Graubünden', 46.4908, 9.8355, 'The original winter resort town — birthplace of winter tourism and host of two Winter Olympics. Engadine valley location with frozen lake, champagne climate (300+ days of sun), and old-money glamour.', 5000, 12000, 'https://www.stmoritz.com', true, 'CHF 600–1,200/month shared.', 'High. Staff housing from luxury hotels essential.', 'Hotel staff accommodation, limited private market.', 'Free town bus. Engadin ski bus connecting Corviglia, Corvatsch, Diavolezza.', 'Town parking available.', 'Engadin Airport (regional). Zürich ~200km (3hr via Julier Pass/train).', 'Julier Pass and Maloja Pass. Can be treacherous. Bernina railway alternative.', 'CHF 500–800/week', 'Coop, Volg.', 'CHF 18–45. Luxury dining.', 'Badrutt''s Palace, Kulm Hotel, Carlton, Suvretta House — world-famous luxury hotels.', 'Very limited — service industry focused.', 'Bobby''s Pub, King''s Social House, Devil''s Place. Good but exclusive scene.', 'Talvo by Dalsass, La Marmite, Chesa Veglia. Michelin-starred options.', 'Ovaverva spa and sports centre (excellent).', 'Luxury retail. Full town services.', 'Snow Polo World Cup, White Turf (horse racing on frozen lake), toboggan events.', 'Spital Oberengadin (hospital).', 'Full services.', 'Old-money glamour, 300 days of sun, frozen lake activities. Less party-focused than Verbier, more elegant.', 'Cosmopolitan — Italian, Portuguese, German, Eastern European service workers.', 'Staff social events, cross-country skiing culture, lake activities.', '-12°C to -2°C but very sunny', 'Good snowfall. Famous for sunshine.', 'Hiking, cycling, sailing on the lakes. Summer tourism.', 'November.', 'St. Moritz worker community.', 'The "champagne climate" is real — cold but incredibly sunny. Working in the Palace hotels is world-class hospitality experience.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='34' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='st-moritz' LIMIT 1), 0, true);

-- ── EUROPE — AUSTRIA ───────────────────────────────────────

-- St. Anton
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('St. Anton', 'st-anton', 'Austria', 'Tyrol', 47.1272, 10.2675, 'The birthplace of alpine skiing and Austria''s most famous party resort. Part of the Ski Arlberg — the largest connected ski area in Austria. Legendary après-ski culture.', 2500, 10000, 'https://www.stantonamarlberg.com', true, '€350–€650/month. Staff housing standard in Austrian resorts.', 'High. Employer housing is the norm.', 'Staff accommodation, pensions.', 'Free ski bus. Train station in town (Arlberg railway).', 'Village parking.', 'Innsbruck Airport ~100km (1hr). Zürich Airport ~200km.', 'A12 motorway via Arlberg tunnel/pass. Well-maintained.', '€350–€500/week', 'Spar, MPreis.', '€10–€20.', 'Hotels, restaurants, ski schools, Ski Arlberg lift company.', 'Limited. Innsbruck for additional opportunities.', 'MooserWirt and Krazy Kanguruh — two of the most famous après bars in the world. Postkeller, Underground.', 'Hospiz Alm, Museum Restaurant, Hotel Post.', 'ARLBERG-well.com spa and fitness.', 'Resort basics, ski shops.', 'White Thrill ski race, New Year celebrations, Tanz in den Mai.', 'Medical centre in resort.', 'Full Austrian emergency services.', 'The original après-ski capital of the world. Austrian gemütlichkeit meets international party culture. Serious skiing by day, legendary partying by night.', 'International — Scandinavian, British, German, Eastern European.', 'MooserWirt at 3pm is a rite of passage. Dancing on tables in ski boots. Seriously fun.', '-8°C to 0°C', 'Heavy snowfall at 1,304m.', 'Summer hiking and mountain biking.', 'November for December start.', 'St. Anton Seasonal Workers Facebook group.', 'The MooserWirt at 3:30pm is one of skiing''s great experiences. Austrian work contracts include social insurance. Learn some German.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='35' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='st-anton' LIMIT 1), 0, true);

-- Kitzbühel
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Kitzbühel', 'kitzbuhel', 'Austria', 'Tyrol', 47.4467, 12.3917, 'A medieval walled town with cobblestone streets and colourful facades. Home to the legendary Hahnenkamm downhill race — the most famous ski race in the world. Upscale but charming.', 8200, 15000, 'https://www.kitzbuehel.com', true, '€300–€600/month. Staff housing available.', 'Moderate.', 'Staff accommodation, pensions, shared apartments.', 'Free ski bus. Lifts accessible from town.', 'Town parking available.', 'Innsbruck Airport ~95km. Salzburg Airport ~80km.', 'Well-connected by motorway. Good roads.', '€300–€500/week', 'Spar, MPreis, Billa.', '€10–€20.', 'Hotels, restaurants, Bergbahn AG (lift company), ski schools.', 'Hospitality in surrounding villages, summer tourism.', 'Londoner (legendary British pub), Stampfl''s, Take Five. Great nightlife.', 'Chizzo, Kupferstube, Neuwirt. Mix of traditional Austrian and modern.', 'Aquarena spa and pool, fitness centres.', 'Full town amenities — medieval centre with modern services.', 'Hahnenkamm Race Week (January — huge global event), Snow Polo, summer festivals.', 'Krankenhaus Kitzbühel (hospital).', 'Full services.', 'Medieval charm meets modern luxury. The Hahnenkamm race week transforms the town. Traditional Austrian culture with international flair.', 'International — Dutch, German, British, Scandinavian. German very helpful.', 'Londoner pub is the social hub. Hahnenkamm race week is the highlight of the season.', '-7°C to 1°C', 'Regular snowfall in town (762m).', 'Golf, hiking, cycling. Summer tourism is significant.', 'November.', 'Kitzbühel worker community.', 'The Hahnenkamm race week in January is electric — the whole town transforms. The Londoner pub has been the staff bar for decades. German language helps enormously.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='36' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='kitzbuhel' LIMIT 1), 0, true);

-- Ischgl
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Ischgl', 'ischgl', 'Austria', 'Tyrol', 47.0153, 10.2928, 'Austria''s glamour resort in the Paznaun Valley. Famous for its Top of the Mountain concerts (Elton John, Robbie Williams have performed) and high-altitude skiing into Switzerland (Samnaun).', 1600, 8000, 'https://www.ischgl.com', true, '€300–€600/month. Employer housing standard.', 'Staff housing provided by most employers.', 'Staff accommodation.', 'Free village buses. Lifts from village centre.', 'Village parking and car parks.', 'Innsbruck Airport ~100km.', 'Paznaun valley road. Silvretta High Alpine Road (summer).', '€350–€500/week', 'Spar, small shops.', '€10–€22. Good restaurant scene.', 'Hotels, restaurants, lift company, ski schools.', 'Very limited — valley is remote.', 'Pacha, Kuhstall, Schatzi, Niki''s Stadl. Party capital of the Tyrol.', 'Trofana Royal (5-star), Lucy Wang, Allegra.', 'Silvretta Center spa.', 'Duty-free shopping in Samnaun (Switzerland).', 'Top of the Mountain concerts (opening and closing), Ironbike.', 'Medical centre in Ischgl.', 'Full services.', 'High-energy party resort. The concerts are massive. Less traditional than other Austrian resorts, more glam.', 'International workforce — German, Eastern European, Scandinavian.', 'Non-stop party season. Top of the Mountain concerts are legendary.', '-8°C to 0°C', 'Good snowfall.', 'Summer hiking and biking along Silvretta High Alpine Road.', 'November.', 'Ischgl worker groups.', 'The duty-free shopping in Samnaun (accessible by ski) is a unique perk. The concert season defines Ischgl.');
