-- Sölden
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Sölden', 'solden', 'Austria', 'Tyrol', 46.9658, 10.8764, 'The Ötztal Arena''s main resort with three 3,000m+ peaks and two glacier ski areas offering early-season skiing from October. Known as a party resort and James Bond filming location (Spectre).', 3300, 10000, 'https://www.soelden.com', true, '€300–€550/month.', 'Staff housing standard.', 'Staff accommodation, pensions.', 'Free ski bus. Lifts from village.', 'Village parking.', 'Innsbruck Airport ~80km (1hr).', 'B186 Ötztal road — well-maintained.', '€300–€500/week', 'Spar, MPreis.', '€10–€20.', 'Hotels, restaurants, lift company, ski schools.', 'Ötztal hospitality, summer glacier skiing jobs.', 'Bla Bla, Lawine, Fire & Ice, Bierhimml. Strong party scene.', 'S-Lounge, Grauer Bär, local restaurants.', 'Freizeit Arena (pool, climbing, gym).', 'Resort basics.', 'FIS Alpine World Cup (October opening), glacier opening parties.', 'Medical centre in Sölden.', 'Full services.', 'High-altitude party resort. The glacier extends the season — skiing from October to May. James Bond atmosphere (007 Elements exhibit).', 'International — German, Dutch, Scandinavian, Eastern European.', 'Party culture, glacier skiing community.', '-8°C to 0°C', 'Good snowfall. Glaciers above.', 'Summer glacier skiing (unique), hiking, cycling.', 'October for glacier season, November for main season.', 'Sölden worker groups.', 'The glacier skiing means an extra-long season — arrive in October for early work. 007 Elements at the summit is worth visiting.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='38' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='solden' LIMIT 1), 0, true);

-- Mayrhofen
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Mayrhofen', 'mayrhofen', 'Austria', 'Tyrol', 47.1667, 11.8667, 'The main town of the Zillertal valley with the steepest groomed run in Austria (Harakiri at 78%). Known for the Snowbombing music festival and excellent Penken ski area.', 3800, 10000, 'https://www.mayrhofen.at', true, '€280–€500/month. Staff housing common.', 'Moderate.', 'Staff accommodation, pensions, shared apartments.', 'Free ski bus. Penkenbahn cable car from town. Zillertalbahn train.', 'Town parking, P&R lots.', 'Innsbruck Airport ~75km (1hr).', 'Zillertal road — well-maintained valley road.', '€300–€450/week', 'Spar, MPreis.', '€8–€18. Very affordable.', 'Hotels, restaurants, Mayrhofner Bergbahnen (lifts), ski schools.', 'Zillertal valley hospitality, summer tourism.', 'Ice Bar, Bruck''n Stadl, Scotland Yard. Good après scene. Snowbombing festival is legendary.', 'Wirtshaus zum Griena, Mo''s, various Austrian restaurants.', 'Erlebnis Sennerei (pool, sauna), climbing centre.', 'Good town amenities for the size.', 'Snowbombing Festival (April — massive electronic music festival), Zillertal valley events.', 'Krankenhaus Schwaz (regional hospital). Town doctor.', 'Full services.', 'Friendly, fun Austrian town. The Snowbombing festival brings international music culture. Great intermediate skiing.', 'International — British, Dutch, German, Scandinavian.', 'Friendly après culture, Snowbombing anticipation, valley festivals.', '-6°C to 2°C', 'Regular snowfall at 630m.', 'Zillertal hiking, via ferrata, summer tourism.', 'November.', 'Mayrhofen worker groups.', 'Snowbombing in April is one of Europe''s best music festivals — in a ski resort. The Harakiri run (78% gradient) is terrifying. Austrian staff contracts come with good social protections.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='39' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='mayrhofen' LIMIT 1), 0, true);

