-- Livigno
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Livigno', 'livigno', 'Italy', 'Lombardy', 46.5386, 10.1350, 'A duty-free town in a remote high-altitude valley near the Swiss border. Livigno is famous for cheap fuel, alcohol, and cigarettes — plus great skiing and a snowboard/freestyle culture.', 7000, 15000, 'https://www.livigno.eu', true, '€300–€500/month.', 'Moderate.', 'Staff accommodation, apartments.', 'Free ski bus connecting the long town to lift stations.', 'Free parking widely available.', 'Closest airports: Innsbruck (~170km), Bergamo (~200km), Zürich (~200km).', 'Access via Foscagno Pass or Munt La Schera tunnel (Switzerland). Can be challenging.', '€250–€400/week (duty-free savings)', 'Multiple supermarkets — DUTY FREE prices on many goods.', '€8–€18. Good Italian food at reasonable prices.', 'Hotels, restaurants, ski schools, sports shops (tons of them — tax-free shopping).', 'Retail (many sports shops), hospitality.', 'Kuhstall, Stalet, Tea del Plan. Fun scene.', 'Excellent Italian dining — pizza, pasta, polenta. Agriturismo options.', 'Aquagranda wellness centre (world-class).', 'Massive amount of sports shops (duty-free). All basics.', 'Freestyle events, snowboard competitions, New Year celebrations.', 'Medical centre in Livigno.', 'Full services.', 'Unique duty-free status creates a shopping paradise. Snowboard/freestyle culture is strong. Italian food, Swiss proximity, tax-free shopping.', 'Italian workers primarily, growing Eastern European and some international.', 'Italian après culture, duty-free shopping sprees, Aquagranda spa visits.', '-10°C to -1°C', 'Good snowfall at 1,816m.', 'Road cycling, mountain biking, hiking, Aquagranda.', 'November.', 'Livigno worker community.', 'The duty-free status means cheap everything — fuel, alcohol, electronics, clothes. Stock up! Aquagranda spa is one of the best in the Alps.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='40' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='livigno' LIMIT 1), 0, true);

-- Cortina d'Ampezzo
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Cortina d''Ampezzo', 'cortina-dampezzo', 'Italy', 'Veneto', 46.5369, 12.1361, 'The "Queen of the Dolomites" — host of the 1956 Winter Olympics and co-host of the 2026 Games. Cortina is Italian glamour at its finest, surrounded by UNESCO-listed Dolomite peaks.', 5800, 12000, 'https://www.dolomiti.org/en/cortina', true, '€350–€600/month.', 'Moderate to high.', 'Staff accommodation, apartments.', 'Free ski bus. Lifts from town edges.', 'Town parking areas.', 'Venice Marco Polo Airport ~160km (2hr). Treviso Airport ~130km.', 'SS51 through Dolomites — scenic but can be snowy. Brenner motorway access.', '€300–€500/week', 'Despar, small shops.', '€10–€25. Excellent Italian cuisine.', 'Hotels, restaurants, Dolomiti Superski, ski schools, 2026 Olympics preparation.', '2026 Olympics infrastructure creating additional jobs.', 'Enoteca, VIP Club. More refined than party-focused.', 'Ra Stua, Il Baita Fraina, Ristorante Tivoli. Dolomite cuisine.', 'Cortina stadium and sports facilities.', 'Designer shops, outdoor sports stores, services.', '2026 Winter Olympics events, Cortina Fashion Weekend, Dolomites cinema.', 'Ospedale di Cortina (hospital).', 'Full services — enhanced for 2026 Olympics.', 'Italian elegance in a UNESCO mountain setting. The 2026 Olympics are transforming the town. More refined than party resorts.', 'Italian workers primarily. Growing international presence for 2026.', 'Italian aperitivo culture, mountain dining, Dolomite via ferrata.', '-8°C to 1°C', 'Good snowfall at 1,224m.', 'Dolomite hiking, via ferrata, cycling. Summer tourism is huge.', 'November.', 'Cortina worker community.', 'The 2026 Olympics mean massive investment and job creation right now. The Dolomites are arguably the most beautiful mountains in the world.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='41' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='cortina-dampezzo' LIMIT 1), 0, true);

-- Breuil-Cervinia
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Breuil-Cervinia', 'breuil-cervinia', 'Italy', 'Aosta Valley', 45.9347, 7.6306, 'The Italian side of the Matterhorn (Cervino in Italian). Connected to Zermatt via lifts — you can literally ski from Italy to Switzerland. High-altitude, snow-sure, with Italian flair.', 600, 5000, 'https://www.cervinia.it', true, '€300–€500/month.', 'Low to moderate. Small community.', 'Staff accommodation, apartments.', 'Ski lifts connect to Zermatt. Village is compact and walkable.', 'Village parking.', 'Turin Airport ~120km (1.5hr). Milan Malpensa ~180km.', 'SR46 valley road. Well-maintained but steep.', '€250–€400/week', 'Small supermarkets.', '€8–€18. Good Italian food.', 'Hotels, restaurants, lift company, ski schools.', 'Limited — small resort village.', 'Quiet village bars. Copa Pan, Dragon Bar.', 'Mountain restaurants (Chalet Etoile is famous), pizzerias, pasta houses.', 'Limited.', 'Small resort amenities, ski shops.', 'Free-ride events, Matterhorn festival celebrations.', 'Medical point in Cervinia. Aosta hospital.', 'Alpine rescue available.', 'Laid-back Italian mountain village with access to one of the world''s most iconic mountains. Less glitzy than Zermatt, more affordable, equally spectacular.', 'Mostly Italian. Some international workers.', 'Quiet, mountain-focused. Italian dinner culture. Ski into Zermatt for variety.', '-8°C to -1°C', 'Heavy snowfall at 2,006m.', 'Summer glacier skiing, hiking.', 'November.', 'Cervinia worker community.', 'You can ski to Zermatt for lunch and back — one of skiing''s great experiences. Italian side is much cheaper than Swiss side for everything.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='42' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='breuil-cervinia' LIMIT 1), 0, true);

-- ── EUROPE — OTHER ─────────────────────────────────────────

-- Åre Village
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Åre Village', 'are-village', 'Sweden', 'Jämtland', 63.3989, 13.0744, 'Scandinavia''s premier ski resort — a charming lakeside village with a long skiing tradition, excellent restaurants, and true Arctic winter conditions. Think Whistler vibes with Swedish hygge.', 3000, 10000, 'https://www.skistar.com/en/are/', true, 'SEK 4,000–7,000/month shared (~€350–€600).', 'Moderate.', 'Staff accommodation from SkiStar, shared apartments.', 'Free ski bus. SJ train station in Åre (direct sleeper train from Stockholm).', 'Village parking.', 'Åre Östersund Airport ~90km (1hr). Stockholm ~600km (6hr train/1hr flight).', 'E14 highway — well-maintained. Winter tyres mandatory.', 'SEK 4,500–6,000/week (~€400–€530)', 'ICA supermarket, small shops.', 'SEK 100–200 (~€9–€17). Swedish fika culture.', 'SkiStar (major employer), hotels, restaurants, outdoor companies.', 'Östersund (15min train) has additional opportunities.', 'Bygget, Diplomat Ski Lodge, Country Club. Good nightlife for Sweden.', 'Copperhill Mountain Lodge (fine dining), Vinbaren, Broken. Excellent food scene.', 'SkiStar gym, sports centre.', 'Good village amenities.', 'Åre Summer Festival, FIS World Cup, Jon Olsson events.', 'Åre Health Centre. Östersund hospital ~90km.', 'Full services.', 'Swedish mountain culture — organised, sustainable, outdoorsy. Fika breaks are mandatory (and wonderful). Northern lights potential.', 'Growing international community — Nordic primarily, some British and Australian.', 'Fika culture, bar nights, Northern Lights watching, cross-country skiing.', '-15°C to -5°C. Proper Arctic cold.', 'Good snowfall. Arctic conditions.', 'Hiking, mountain biking, fishing. Midnight sun in summer.', 'November.', 'Åre seasonal worker groups.', 'The sleeper train from Stockholm is the civilised way to arrive. Swedish working conditions are excellent (regulated hours, good pay). Bring serious cold-weather gear.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='8' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='are-village' LIMIT 1), 0, true);

-- Gudauri (Tbilisi as base)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Gudauri', 'gudauri', 'Georgia', 'Mtskheta-Mtianeti', 42.4578, 44.4706, 'A rapidly developing Georgian ski resort on the Greater Caucasus range. Gudauri offers incredible freeride terrain, incredibly affordable living, and Georgian hospitality (khachapuri and wine included).', 200, 3000, 'https://www.gudauri.info', false, 'GEL 800–1,500/month (~€250–€480). Tbilisi: GEL 600–1,200.', 'Low. Rapidly building new accommodation.', 'Guesthouses, hotels, Tbilisi apartments (2hr commute).', 'Marshrutka (minibus) from Tbilisi (2hr). Some resort shuttles. Many workers drive.', 'Free parking.', 'Tbilisi International Airport ~120km (2hr).', 'Georgian Military Highway — spectacular but can be treacherous. Gudauri pass can close in storms.', 'GEL 500–800/week (~€160–€260). Extremely affordable.', 'Small shops in Gudauri. Full options in Tbilisi.', 'GEL 10–25 (~€3–€8). Incredible Georgian food at absurdly low prices.', 'Hotels, restaurants, ski schools, guide companies, property developers.', 'Tbilisi has a booming tourism and tech economy.', 'Gudauri has a small but growing après scene. Tbilisi nightlife is legendary (Bassiani, Cafe Gallery).', 'Georgian cuisine is exceptional — khinkali (dumplings), khachapuri (cheese bread), wine. Everything is affordable.', 'Small gyms in hotels.', 'Basic in Gudauri. Full city services in Tbilisi.', 'New Year celebrations, Georgian festivals, Tbilisi cultural events.', 'Basic medical in Gudauri. Tbilisi has modern hospitals.', 'Emergency services developing. Mountain rescue available.', 'Frontier ski culture — wild, developing, adventurous. Georgia is one of the world''s most hospitable countries. The food and wine are incredible.', 'Growing international freeride community — French, Russian, Eastern European.', 'Gudauri is small and social. Tbilisi is a world-class city for weekends.', '-8°C to 0°C at resort. Tbilisi: 0°C to 6°C', 'Heavy snowfall at resort (2,200m). Tbilisi rarely sees snow.', 'Tbilisi is a fantastic summer city. Hiking in the Caucasus.', 'December.', 'Gudauri ski community groups.', 'Georgia is the best-value ski destination in the world right now. The food alone is worth the trip. Tbilisi is an incredible weekend city. Get travel insurance — medical care is basic at the resort.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='9' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='gudauri' LIMIT 1), 0, true);

-- Soldeu (Grandvalira)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Soldeu', 'soldeu', 'Andorra', 'Canillo', 42.5764, 1.6672, 'A small Pyrenean village in Andorra — one of the Grandvalira resort stations. Andorra''s duty-free status makes it affordable. Compact, friendly, and increasingly international.', 600, 3000, 'https://www.grandvalira.com', true, '€350–€550/month shared. Andorra la Vella cheaper.', 'Moderate.', 'Staff accommodation, shared apartments, Andorra la Vella commute.', 'Free Grandvalira ski bus between villages. Regular bus to Andorra la Vella.', 'Free parking at resort.', 'Toulouse Airport ~195km (2.5hr). Barcelona Airport ~205km (2.5hr).', 'CG-2 road through Andorra — generally good. Envalira tunnel/pass.', '€300–€450/week (duty-free savings)', 'Small shops. Better in Andorra la Vella (duty-free prices).', '€8–€18.', 'Hotels, restaurants, Grandvalira, ski schools (particularly British ski schools).', 'Duty-free retail in Andorra la Vella. Summer tourism.', 'Fat Albert''s, Pussycat, Sol i Neu. British-influenced après.', 'El Celler, Sol i Neu, mountain restaurants.', 'Caldea spa (Andorra la Vella — enormous thermal spa).', 'Duty-free shopping is Andorra''s defining feature. Perfume, electronics, alcohol.', 'FIS World Cup events, Andorran festivals, Caldea events.', 'Soldeu medical centre. Andorra la Vella hospital.', 'Full Andorran services.', 'Small, friendly, duty-free. A uniquely affordable European ski base. The microstate setting is quirky and fun.', 'British ski school workers, Spanish, French, Eastern European.', 'Pub nights, Caldea spa trips, duty-free shopping sprees, trips to Barcelona.', '-5°C to 2°C', 'Good snowfall at 1,710m.', 'Hiking, Caldea spa, duty-free shopping draws visitors year-round.', 'November.', 'Grandvalira seasonal worker groups.', 'Andorra is a tax haven — no income tax. Duty-free shopping is genuinely excellent. Caldea spa is massive and worth multiple visits. Barcelona is a cheap flight away.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='10' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='soldeu' LIMIT 1), 0, true);

-- ── SOUTH AMERICA ──────────────────────────────────────────

-- San Carlos de Bariloche (Cerro Catedral)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('San Carlos de Bariloche', 'bariloche', 'Argentina', 'Río Negro', -41.1335, -71.3103, 'The chocolate capital of Argentina, set on the shores of Lago Nahuel Huapi in Patagonia. A charming lakeside city with Swiss-influenced architecture, famous for chocolate, craft beer, and outdoor adventure.', 115000, 130000, 'https://www.barilocheturismo.gob.ar', true, 'ARS 150,000–300,000/month (~USD $150–$300). Very affordable.', 'Low to moderate. Affordable market.', 'Hostels, shared apartments, short-term rentals.', 'Catedral Bus from Bariloche to Cerro Catedral (20km, frequent service).', 'Free parking at many locations.', 'Bariloche Airport (San Carlos de Bariloche) — in town. Buenos Aires ~2hr flight.', 'Ruta 40 and lakeside roads — generally good. Snow possible.', 'ARS 200,000–350,000/week (~USD $200–$350). Very affordable.', 'La Anónima, Carrefour, many options.', 'ARS 5,000–15,000 (~USD $5–$15). Incredible value.', 'Cerro Catedral, hotels, chocolate shops, restaurants, outdoor companies.', 'Chocolate industry, craft breweries, tourism, summer outdoor activities.', 'Mamushka, Cervecería Patagonia, Los Vikings, Wilkenny. Fun nightlife scene.', 'Cassis, Il Gabbiano, craft breweries. Famous chocolate shops (Rapa Nui, Mamuschka).', 'Gyms and outdoor fitness.', 'Full city amenities. Chocolate shops everywhere.', 'Fiesta Nacional de la Nieve (National Snow Festival), chocolate festivals, craft beer events.', 'Hospital Zonal Bariloche, clinics.', 'Full services.', 'Patagonian adventure city with Swiss/German cultural influences. Chocolate, craft beer, lakes, and mountains. Affordable and beautiful.', 'Argentine workers plus some international seasonal workers (Brazilian, Chilean).', 'Craft beer culture, chocolate tastings, lake adventures, Patagonian BBQ.', '-2°C to 8°C. Milder than Northern Hemisphere resorts.', 'Occasional snow in town.', 'Stunning summer — hiking, kayaking, fly fishing in Patagonia. Equally beautiful as winter.', 'June for July season start (Southern Hemisphere winter).', 'Bariloche seasonal worker communities.', 'The Argentine peso makes this incredibly affordable for international workers. The chocolate is world-class. Lake Nahuel Huapi is stunning.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='55' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='bariloche' LIMIT 1), 20, true);

-- Los Andes (Portillo)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Los Andes', 'los-andes', 'Chile', 'Valparaíso', -32.8333, -70.5958, 'A small Aconcagua Valley city at the foot of the Andes, serving as the nearest town to Portillo ski resort. Agricultural town with Chilean small-city character.', 66000, 68000, 'https://www.portillo.cl', true, 'CLP 200,000–350,000/month (~USD $220–$380). Affordable.', 'Low. Portillo provides all-inclusive lodging for staff.', 'Portillo is all-inclusive — most workers live at the resort. Los Andes for independent lodging.', 'Portillo provides staff transport. Los Andes to Portillo ~60km (1.5hr mountain road).', 'Free at Portillo. Town parking available.', 'Santiago International Airport ~140km (2hr). Los Andes is en route.', 'Ruta 60 international highway to Argentina. Mountain road to Portillo — well-maintained but steep.', 'CLP 150,000–250,000/week (~USD $165–$275)', 'Jumbo, Lider, small shops.', 'CLP 4,000–8,000 (~USD $4–$9).', 'Portillo (all-inclusive resort — almost all staff live on-site), local agriculture.', 'Agricultural work, Santiago commute.', 'Limited in Los Andes. Portillo has its own bar scene (legendary — it''s a captive audience at 2,880m).', 'Portillo restaurant (included for staff). Los Andes has Chilean restaurants.', 'Limited.', 'Full small-city amenities.', 'Portillo season opening/closing parties are legendary.', 'Los Andes hospital. Portillo has medical station.', 'Full services.', 'Portillo is a unique all-inclusive experience — everyone eats, sleeps, and parties together at 2,880m. Like a cruise ship on a mountain.', 'Chilean workers, plus international ski teams (resort is a training base for national teams).', 'Portillo''s enclosed community creates intense social bonds. Everyone knows everyone.', '-3°C to 8°C in Los Andes. Portillo: -8°C to 2°C', 'No snow in Los Andes (valley). Heavy snow at Portillo.', 'Aconcagua Valley wine region. Los Andes has summer tourism.', 'June for July start.', 'Portillo worker community.', 'Portillo is an all-inclusive experience — you''ll live, eat, and socialise entirely at the resort. The sunset over the Laguna del Inca is one of skiing''s great sights.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='56' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='los-andes' LIMIT 1), 60, true);

-- Santiago (Valle Nevado)
INSERT INTO nearby_towns (name, slug, country, state_region, latitude, longitude, description, population_permanent, population_seasonal, website, staff_housing_available, avg_rent_weekly, housing_demand, temporary_stay_options, public_transport_to_resort, parking_availability, distance_to_airport, road_conditions, weekly_cost_estimate, supermarkets, eating_out, local_employers, extra_job_opportunities, bars_nightlife, restaurants_cafes, gyms_fitness, shops_services, events_festivals, medical_facilities, emergency_services, vibe_atmosphere, international_workforce, social_life, avg_winter_temp, snowfall_in_town, summer_appeal, best_time_to_arrive, community_groups, insider_tips)
VALUES ('Santiago', 'santiago', 'Chile', 'Santiago Metropolitan', -33.4489, -70.6693, 'A massive South American capital of 7 million people that happens to have world-class skiing just 60km up the mountain. Valle Nevado is the closest major resort. Workers can live in a global city and commute to ski.', 7000000, 7000000, 'https://www.vallenevado.com', false, 'CLP 300,000–600,000/month (~USD $330–$660) for shared apartment in Santiago.', 'Low — massive city housing market.', 'Hostels, shared apartments, Airbnb. Huge market.', 'Ski bus services from Santiago (2hr up the mountain). Estaciones service. Some employers provide transport.', 'City parking and resort parking both available.', 'Santiago International Airport — in the city. Major international hub.', 'G-21 road (Farellones road) — steep, 40 hairpin turns. Can require chains. Often closes in storms.', 'CLP 250,000–400,000/week (~USD $275–$440)', 'Jumbo, Lider, countless options. Full city supermarket selection.', 'CLP 5,000–15,000 (~USD $5–$16). Every cuisine imaginable.', 'Valle Nevado resort, El Colorado, Farellones, Santiago hospitality.', 'Enormous city economy — every industry represented.', 'Bellavista neighbourhood (Patio Bellavista), Barrio Italia, Lastarria. World-class nightlife.', 'Every cuisine. Santiago is a foodie city. Central Market seafood is legendary.', 'Tons of gyms, CrossFit boxes, swimming pools.', 'Full city services — everything you could need.', 'Festivals, concerts, cultural events year-round. Santiago a Mil theatre festival.', 'World-class hospitals and clinics.', 'Full city services.', 'The only ski resort where your base town is a capital city of 7 million people. Best of both worlds — city life and skiing in the same day.', 'Chilean workforce. International expat community in Santiago.', 'City nightlife, cultural events, restaurants, weekend skiing.', '3°C to 14°C in Santiago winter (mild). Valle Nevado: -8°C to 2°C', 'Never snows in Santiago.', 'Santiago is a year-round city. Wine regions nearby. Coastal cities accessible.', 'June.', 'Santiago expat and ski communities.', 'The 40-hairpin-turn road to Valle Nevado is an experience itself. Living in Santiago gives you city life during the week and skiing on weekends. Chilean ski season is June–September.');
INSERT INTO resort_nearby_towns (resort_id, town_id, distance_km, is_primary) VALUES ((SELECT id FROM resorts WHERE legacy_id='6' LIMIT 1), (SELECT id FROM nearby_towns WHERE slug='santiago' LIMIT 1), 60, true);
